window.QUESTIONS = [
// ===== 第1章：簿記の基本 =====
// ch1-1 簿記の目的と種類
{id:1,ch:1,themeId:"ch1-1",type:"choice",diff:1,q:"簿記の最も重要な目的はどれですか？",opts:["企業の財政状態と経営成績を明らかにする","税金をできるだけ安くする","商品の在庫数量を管理する","社員の給料を計算する"],ans:0,exp:"簿記の目的は、企業の財政状態（貸借対照表）と一定期間の経営成績（損益計算書）を明らかにすることです。税金計算や在庫管理はその一部ですが、最重要目的は財政状態と経営成績の把握です。"},
{id:2,ch:1,themeId:"ch1-1",type:"choice",diff:1,q:"複式簿記の説明として正しいものはどれですか？",opts:["すべての取引を借方と貸方の両面から記録する","収入と支出だけを記録する","現金の動きだけを記録する","売上と仕入だけを記録する"],ans:0,exp:"複式簿記はすべての取引を必ず借方（左）と貸方（右）の両面から記録します。これにより、自己検証機能（借方合計＝貸方合計）が働き、記録の誤りを発見しやすくなります。"},
{id:3,ch:1,themeId:"ch1-1",type:"choice",diff:1,q:"日商簿記3級で学ぶのはどのような企業の簿記ですか？",opts:["小規模な個人商店・小規模会社の商業簿記","大企業の工業簿記","金融機関の特殊な簿記","農業経営の簿記"],ans:0,exp:"日商簿記3級は、小規模な個人商店や中小会社を対象とした商業簿記を学びます。商品を仕入れて販売する商業の取引を中心に扱います。"},
{id:4,ch:1,themeId:"ch1-1",type:"choice",diff:1,q:"財政状態を表す財務諸表はどれですか？",opts:["貸借対照表","損益計算書","精算表","仕訳帳"],ans:0,exp:"財政状態（資産・負債・純資産の状況）を表すのは貸借対照表（B/S）です。損益計算書は一定期間の経営成績（収益・費用・利益）を表します。"},
{id:5,ch:1,themeId:"ch1-1",type:"choice",diff:1,q:"経営成績を表す財務諸表はどれですか？",opts:["損益計算書","貸借対照表","商品有高帳","現金出納帳"],ans:0,exp:"経営成績（一定期間の収益・費用・利益）を表すのは損益計算書（P/L）です。「いくら儲かったか」を示す財務諸表です。"},
{id:6,ch:1,themeId:"ch1-1",type:"choice",diff:2,q:"単式簿記と複式簿記の違いとして正しいものはどれですか？",opts:["複式簿記は借方・貸方の両面から記録するが、単式簿記は一面のみ記録する","複式簿記は2冊の帳簿を使い、単式簿記は1冊だけ使う","複式簿記は2人で記録し、単式簿記は1人で記録する","複式簿記は2倍の金額を記録する"],ans:0,exp:"単式簿記は家計簿のように収入・支出の一面だけを記録します。複式簿記はすべての取引を借方・貸方の両面から記録するため、財産の変動全体を把握できます。"},
{id:7,ch:1,themeId:"ch1-1",type:"choice",diff:2,q:"簿記上の「取引」として正しいものはどれですか？",opts:["商品を5,000円で販売し現金を受け取った","来月の商品購入を口頭で約束した","銀行から融資の内諾を得た","新しい従業員を採用する契約をした"],ans:0,exp:"簿記上の取引とは、資産・負債・純資産・収益・費用に実際に増減が生じる出来事です。口頭の約束や契約締結だけでは簿記上の取引にはなりません。"},

// ch1-2 資産・負債・純資産の概念
{id:8,ch:1,themeId:"ch1-2",type:"choice",diff:1,q:"次のうち「資産」に分類されるものはどれですか？",opts:["売掛金","買掛金","資本金","売上"],ans:0,exp:"売掛金は代金をまだ受け取っていない権利（お金を受け取る権利）なので資産です。買掛金は負債、資本金は純資産、売上は収益に分類されます。"},
{id:9,ch:1,themeId:"ch1-2",type:"choice",diff:1,q:"次のうち「負債」に分類されるものはどれですか？",opts:["借入金","現金","受取手形","受取利息"],ans:0,exp:"借入金は銀行などから借りているお金なので、将来返済する義務（負債）です。現金は資産、受取手形は資産、受取利息は収益です。"},
{id:10,ch:1,themeId:"ch1-2",type:"choice",diff:1,q:"貸借対照表等式として正しいものはどれですか？",opts:["資産＝負債＋純資産","資産＝負債－純資産","資産＋負債＝純資産","収益－費用＝純資産"],ans:0,exp:"貸借対照表等式は「資産＝負債＋純資産」です。企業が持つ財産（資産）は、他人から借りた分（負債）と自己資本（純資産）の合計に等しくなります。"},
{id:11,ch:1,themeId:"ch1-2",type:"calc",diff:1,q:"資産の合計が800,000円、負債の合計が300,000円のとき、純資産はいくらですか？",ans:500000,unit:"円",exp:"純資産＝資産－負債＝800,000－300,000＝500,000円です。貸借対照表等式「資産＝負債＋純資産」を変形すると「純資産＝資産－負債」になります。"},
{id:12,ch:1,themeId:"ch1-2",type:"choice",diff:2,q:"次のうち「純資産」に分類されるものはどれですか？",opts:["資本金","支払手形","貸付金","仕入"],ans:0,exp:"資本金は事業主が出資した元手なので純資産です。支払手形は負債、貸付金は資産、仕入は費用に分類されます。"},
{id:13,ch:1,themeId:"ch1-2",type:"calc",diff:2,q:"資産1,200,000円、純資産400,000円のとき、負債はいくらですか？",ans:800000,unit:"円",exp:"負債＝資産－純資産＝1,200,000－400,000＝800,000円です。「資産＝負債＋純資産」から「負債＝資産－純資産」と変形して計算します。"},
{id:14,ch:1,themeId:"ch1-2",type:"choice",diff:2,q:"当期純利益が発生したとき、純資産はどうなりますか？",opts:["増加する","減少する","変化しない","負債が増える"],ans:0,exp:"当期純利益（収益－費用）が発生すると、その分だけ純資産が増加します。利益は企業の自己資本を増やすため、純資産に加算されます。"},

// ch1-3 借方と貸方の基本ルール
{id:15,ch:1,themeId:"ch1-3",type:"choice",diff:1,q:"資産が増加したとき、どちらに記録しますか？",opts:["借方（左側）","貸方（右側）","どちらでもよい","上段"],ans:0,exp:"資産の増加は借方（左側）に記録します。「資産の増加＝借方」「資産の減少＝貸方」というルールをしっかり覚えましょう。"},
{id:16,ch:1,themeId:"ch1-3",type:"choice",diff:1,q:"負債が増加したとき、どちらに記録しますか？",opts:["貸方（右側）","借方（左側）","どちらでもよい","下段"],ans:0,exp:"負債の増加は貸方（右側）に記録します。資産とは逆で「負債の増加＝貸方」「負債の減少＝借方」となります。"},
{id:17,ch:1,themeId:"ch1-3",type:"choice",diff:1,q:"費用が発生したとき、どちらに記録しますか？",opts:["借方（左側）","貸方（右側）","どちらでもよい","科目による"],ans:0,exp:"費用の発生は借方（左側）に記録します。給料・仕入・減価償却費など、すべての費用は借方に記録します。"},
{id:18,ch:1,themeId:"ch1-3",type:"choice",diff:1,q:"収益が発生したとき、どちらに記録しますか？",opts:["貸方（右側）","借方（左側）","どちらでもよい","科目による"],ans:0,exp:"収益の発生は貸方（右側）に記録します。売上・受取利息・受取家賃など、すべての収益は貸方に記録します。"},
{id:19,ch:1,themeId:"ch1-3",type:"choice",diff:2,q:"純資産が増加したとき、どちらに記録しますか？",opts:["貸方（右側）","借方（左側）","どちらでもよい","増減なし"],ans:0,exp:"純資産の増加は貸方（右側）に記録します。収益と同様に「純資産の増加＝貸方」です。資本金を出資した場合も貸方に記録します。"},
{id:20,ch:1,themeId:"ch1-3",type:"choice",diff:2,q:"次の勘定科目のうち、残高が借方（左側）に現れるものはどれですか？",opts:["現金","売上","借入金","資本金"],ans:0,exp:"現金は資産なので、通常は借方残高（左側）になります。売上・借入金・資本金は収益・負債・純資産なので、通常は貸方残高（右側）になります。"},
{id:21,ch:1,themeId:"ch1-3",type:"choice",diff:2,q:"仕訳において、借方合計と貸方合計の関係として正しいものはどれですか？",opts:["必ず等しくなる","借方が大きくなる","貸方が大きくなる","科目数が同じになる"],ans:0,exp:"複式簿記では、1つの取引を借方・貸方の両面から記録するため、1件の仕訳の借方合計と貸方合計は必ず等しくなります。これが自己検証機能の基礎です。"},

// ch1-4 仕訳のルールと考え方
{id:22,ch:1,themeId:"ch1-4",type:"journal",diff:1,q:"商品10,000円を現金で販売した。",entries:[{dr:"現金",cr:"売上",amt:10000}],exp:"現金（資産）が増加→借方に現金10,000円。売上（収益）が発生→貸方に売上10,000円。「資産増加＝借方、収益発生＝貸方」の基本ルール通りです。"},
{id:23,ch:1,themeId:"ch1-4",type:"journal",diff:1,q:"文房具（消耗品）3,000円を現金で購入した。",entries:[{dr:"消耗品費",cr:"現金",amt:3000}],exp:"消耗品費（費用）が発生→借方に消耗品費3,000円。現金（資産）が減少→貸方に現金3,000円。費用の発生は借方、資産の減少は貸方です。"},
{id:24,ch:1,themeId:"ch1-4",type:"journal",diff:1,q:"銀行から100,000円を借り入れ、現金で受け取った。",entries:[{dr:"現金",cr:"借入金",amt:100000}],exp:"現金（資産）が増加→借方に現金100,000円。借入金（負債）が増加→貸方に借入金100,000円。「資産増加＝借方、負債増加＝貸方」です。"},
{id:25,ch:1,themeId:"ch1-4",type:"journal",diff:1,q:"A社から商品20,000円を仕入れ、代金は現金で支払った。",entries:[{dr:"仕入",cr:"現金",amt:20000}],exp:"仕入（費用）が発生→借方に仕入20,000円。現金（資産）が減少→貸方に現金20,000円。三分法では商品の仕入を「仕入」勘定（費用）で処理します。"},
{id:26,ch:1,themeId:"ch1-4",type:"journal",diff:2,q:"事業を開始するため、現金500,000円を元手として投資した。",entries:[{dr:"現金",cr:"資本金",amt:500000}],exp:"現金（資産）が増加→借方に現金500,000円。資本金（純資産）が増加→貸方に資本金500,000円。事業開始時の出資は「資本金」勘定で処理します。"},
{id:27,ch:1,themeId:"ch1-4",type:"journal",diff:2,q:"友人に現金50,000円を貸し付けた。",entries:[{dr:"貸付金",cr:"現金",amt:50000}],exp:"貸付金（資産）が増加→借方に貸付金50,000円。現金（資産）が減少→貸方に現金50,000円。お金を貸した権利は「貸付金」という資産になります。"},
{id:28,ch:1,themeId:"ch1-4",type:"choice",diff:2,q:"仕訳を行う手順として正しい順序はどれですか？",opts:["取引の内容把握→増減する勘定科目の特定→借方・貸方の決定→金額の記入","金額の記入→借方・貸方の決定→勘定科目の特定→取引内容の把握","借方・貸方の決定→金額記入→科目特定→内容確認","金額確認→科目選択→仕訳帳記入→転記"],ans:0,exp:"仕訳の手順は①取引の把握②関係する勘定科目の特定③各科目が資産・負債等のどれかを確認④増減のルールに従って借方・貸方を決定⑤金額を記入の順です。"},

// ch1-5 勘定科目の分類と覚え方
{id:29,ch:1,themeId:"ch1-5",type:"choice",diff:1,q:"次のうち「資産」の勘定科目はどれですか？",opts:["受取手形","支払手形","受取家賃","支払家賃"],ans:0,exp:"受取手形は将来お金を受け取れる権利（資産）です。支払手形は将来支払う義務（負債）、受取家賃は収益、支払家賃は費用です。「受取」は資産か収益、「支払」は負債か費用と覚えましょう。"},
{id:30,ch:1,themeId:"ch1-5",type:"choice",diff:1,q:"次のうち「費用」の勘定科目はどれですか？",opts:["減価償却費","減価償却累計額","未収収益","前受収益"],ans:0,exp:"減価償却費は固定資産の価値減少を費用として計上する勘定科目（費用）です。減価償却累計額は負債側の控除項目（評価勘定）、未収収益は資産、前受収益は負債です。"},
{id:31,ch:1,themeId:"ch1-5",type:"choice",diff:1,q:"次のうち「収益」の勘定科目はどれですか？",opts:["受取利息","支払利息","未払利息","前払利息"],ans:0,exp:"受取利息は利息を受け取ったときの収益です。支払利息は費用、未払利息は負債（未払費用）、前払利息は資産（前払費用）に分類されます。"},
{id:32,ch:1,themeId:"ch1-5",type:"choice",diff:2,q:"次のうち「負債」の勘定科目はどれですか？",opts:["前受収益","前払費用","未収収益","受取手形"],ans:0,exp:"前受収益はまだサービスを提供していないのに先にもらったお金で、将来サービスを提供する義務（負債）です。前払費用は資産、未収収益は資産、受取手形は資産です。"},
{id:33,ch:1,themeId:"ch1-5",type:"choice",diff:2,q:"「貸倒引当金」の分類として正しいものはどれですか？",opts:["資産のマイナス（評価勘定）","負債","費用","純資産"],ans:0,exp:"貸倒引当金は売掛金・受取手形などから差し引く評価勘定で、貸借対照表の資産の部にマイナス表示されます。「貸倒引当金繰入」（費用）とは別物です。"},
{id:34,ch:1,themeId:"ch1-5",type:"choice",diff:2,q:"「引出金」の分類として正しいものはどれですか？",opts:["純資産のマイナス（資本金の控除）","資産","費用","負債"],ans:0,exp:"引出金は事業主が事業から私的にお金を引き出したことを記録する勘定で、純資産（資本金）のマイナス項目です。決算時に資本金から差し引きます。"},
{id:35,ch:1,themeId:"ch1-5",type:"choice",diff:3,q:"次の5つの科目を資産・負債・純資産・収益・費用に正しく分類した組み合わせはどれですか？【繰越商品・前受金・資本金・売上・仕入】",opts:["資産・負債・純資産・収益・費用の順","負債・資産・純資産・費用・収益の順","資産・純資産・負債・収益・費用の順","費用・負債・資産・収益・純資産の順"],ans:0,exp:"繰越商品は資産（期末の商品在庫）、前受金は負債（前受け）、資本金は純資産、売上は収益、仕入は費用です。この5つの分類は基本中の基本です。"},

// ===== 第2章：各種取引の仕訳 =====
// ch2-1 現金・当座預金・普通預金取引
{id:36,ch:2,themeId:"ch2-1",type:"journal",diff:1,q:"現金50,000円を普通預金口座に預け入れた。",entries:[{dr:"普通預金",cr:"現金",amt:50000}],exp:"現金（資産）が減少→貸方に現金50,000円。普通預金（資産）が増加→借方に普通預金50,000円。現金を預金に移すだけで、資産の内訳が変わります。"},
{id:37,ch:2,themeId:"ch2-1",type:"journal",diff:1,q:"普通預金口座から現金30,000円を引き出した。",entries:[{dr:"現金",cr:"普通預金",amt:30000}],exp:"現金（資産）が増加→借方に現金30,000円。普通預金（資産）が減少→貸方に普通預金30,000円。引き出しは預金→現金への資産の振替です。"},
{id:38,ch:2,themeId:"ch2-1",type:"journal",diff:1,q:"商品80,000円を販売し、代金は現金で受け取った。",entries:[{dr:"現金",cr:"売上",amt:80000}],exp:"現金（資産）増加→借方、売上（収益）発生→貸方。最も基本的な現金売上の仕訳です。"},
{id:39,ch:2,themeId:"ch2-1",type:"journal",diff:1,q:"商品45,000円を仕入れ、代金は現金で支払った。",entries:[{dr:"仕入",cr:"現金",amt:45000}],exp:"仕入（費用）発生→借方、現金（資産）減少→貸方。三分法では商品の購入を「仕入」勘定（費用）で処理します。"},
{id:40,ch:2,themeId:"ch2-1",type:"journal",diff:2,q:"得意先から売掛金の回収として他社振出の小切手120,000円を受け取った。",entries:[{dr:"現金",cr:"売掛金",amt:120000}],exp:"他社（取引先）が振り出した小切手は、受け取った時点で現金と同様に扱います（通貨代用証券）。現金（資産）増加→借方、売掛金（資産）減少→貸方。"},
{id:41,ch:2,themeId:"ch2-1",type:"journal",diff:1,q:"現金200,000円を当座預金口座に預け入れた。",entries:[{dr:"当座預金",cr:"現金",amt:200000}],exp:"当座預金（資産）増加→借方、現金（資産）減少→貸方。当座預金は小切手を振り出すための預金口座です。"},
{id:42,ch:2,themeId:"ch2-1",type:"journal",diff:2,q:"買掛金60,000円の支払いのため、小切手を振り出して渡した。",entries:[{dr:"買掛金",cr:"当座預金",amt:60000}],exp:"小切手を振り出すと当座預金から引き落とされます。買掛金（負債）減少→借方、当座預金（資産）減少→貸方。"},
{id:43,ch:2,themeId:"ch2-1",type:"journal",diff:2,q:"小口現金の設定として、現金40,000円を小口現金係に渡した。",entries:[{dr:"小口現金",cr:"現金",amt:40000}],exp:"小口現金（資産）増加→借方、現金（資産）減少→貸方。小口現金は日常の細かい支出のために用意する少額の現金です。"},
{id:44,ch:2,themeId:"ch2-1",type:"journal",diff:2,q:"小口現金係から支払報告を受けた。交通費3,000円、消耗品費2,000円、計5,000円。現金5,000円で補充した。",entries:[{dr:"旅費交通費",cr:"現金",amt:3000},{dr:"消耗品費",cr:"現金",amt:2000}],exp:"小口現金の補充時は、実際に使った費用を借方に記録し、補充した現金を貸方に記録します。小口現金残高は変わりません（減った分を補充するため）。"},
{id:45,ch:2,themeId:"ch2-1",type:"journal",diff:2,q:"現金を実際に数えたところ帳簿残高より3,000円多かった。",entries:[{dr:"現金",cr:"現金過不足",amt:3000}],exp:"現金が帳簿より多い（現金超過）場合は、現金（資産）増加→借方、現金過不足（貸方）。原因不明の差額は「現金過不足」勘定で一時的に処理します。"},
{id:46,ch:2,themeId:"ch2-1",type:"journal",diff:2,q:"現金を実際に数えたところ帳簿残高より2,000円少なかった。",entries:[{dr:"現金過不足",cr:"現金",amt:2000}],exp:"現金が帳簿より少ない（現金不足）場合は、現金過不足（借方）、現金（資産）減少→貸方。原因が判明するまで現金過不足勘定で処理します。"},
{id:47,ch:2,themeId:"ch2-1",type:"journal",diff:3,q:"決算において、現金過不足の借方残高1,500円の原因が不明のため、適切に処理した。",entries:[{dr:"雑損",cr:"現金過不足",amt:1500}],exp:"決算時に現金過不足（借方残高）の原因が不明な場合は「雑損」（費用）として処理します。貸方残高なら「雑益」（収益）として処理します。"},
{id:48,ch:2,themeId:"ch2-1",type:"calc",diff:2,q:"当座預金の期首残高500,000円、当月預入合計800,000円、当月引出合計650,000円のとき、期末残高はいくらですか？",ans:650000,unit:"円",exp:"期末残高＝期首残高＋預入合計－引出合計＝500,000＋800,000－650,000＝650,000円。当座預金出納帳の残高計算の基本パターンです。"},
{id:49,ch:2,themeId:"ch2-1",type:"calc",diff:2,q:"現金の期首残高100,000円、当月受取合計350,000円、当月支払合計320,000円のとき、期末残高はいくらですか？",ans:130000,unit:"円",exp:"期末残高＝期首残高＋受取合計－支払合計＝100,000＋350,000－320,000＝130,000円。現金出納帳の残高計算の基本です。"},
{id:50,ch:2,themeId:"ch2-1",type:"choice",diff:3,q:"銀行から送られてきた当座預金の残高証明書（通帳）の残高と帳簿残高が一致しない原因として正しいものはどれですか？",opts:["振り出した小切手がまだ銀行に呈示されていない（未取立小切手）","帳簿を2回つけてしまった","現金と間違えて記帳した","銀行が倒産しそうになっている"],ans:0,exp:"振り出した小切手が相手方にまだ呈示されていない場合（未取立小切手）、帳簿では引き落とし済みでも銀行口座はまだ減っていないため残高が一致しません。"},

// ch2-2 売掛金・受取手形
{id:51,ch:2,themeId:"ch2-2",type:"journal",diff:1,q:"B商店に商品150,000円を販売し、代金は掛けとした。",entries:[{dr:"売掛金",cr:"売上",amt:150000}],exp:"売掛金（資産）増加→借方、売上（収益）発生→貸方。掛けで売った場合は現金の代わりに「売掛金」（後でもらえる権利）が増えます。"},
{id:52,ch:2,themeId:"ch2-2",type:"journal",diff:1,q:"B商店の売掛金90,000円を現金で回収した。",entries:[{dr:"現金",cr:"売掛金",amt:90000}],exp:"現金（資産）増加→借方、売掛金（資産）減少→貸方。売掛金を回収すると、売掛金という資産が現金という資産に変わります。"},
{id:53,ch:2,themeId:"ch2-2",type:"journal",diff:2,q:"売掛金70,000円を、得意先振出の約束手形で受け取った。",entries:[{dr:"受取手形",cr:"売掛金",amt:70000}],exp:"受取手形（資産）増加→借方、売掛金（資産）減少→貸方。手形を受け取ることで、売掛金という資産が受取手形という資産に変わります。"},
{id:54,ch:2,themeId:"ch2-2",type:"journal",diff:2,q:"期日が来た受取手形200,000円が当座預金に入金された。",entries:[{dr:"当座預金",cr:"受取手形",amt:200000}],exp:"当座預金（資産）増加→借方、受取手形（資産）減少→貸方。手形の期日が来て銀行に入金されると、受取手形から当座預金に振り替わります。"},
{id:55,ch:2,themeId:"ch2-2",type:"journal",diff:2,q:"売上返品があり、売掛金30,000円を減額した。",entries:[{dr:"売上",cr:"売掛金",amt:30000}],exp:"売上（収益）の減少→借方、売掛金（資産）の減少→貸方。返品があると売上を取り消し、対応する売掛金も減らします。"},
{id:56,ch:2,themeId:"ch2-2",type:"journal",diff:3,q:"売掛金50,000円を電子記録債権に振り替えた。",entries:[{dr:"電子記録債権",cr:"売掛金",amt:50000}],exp:"電子記録債権（資産）増加→借方、売掛金（資産）減少→貸方。電子記録債権は紙の手形の代わりに電子システムで管理する債権です。"},
{id:57,ch:2,themeId:"ch2-2",type:"journal",diff:2,q:"C社の売掛金40,000円が貸し倒れた。なお貸倒引当金の残高は30,000円である。",entries:[{dr:"貸倒引当金",cr:"売掛金",drAmt:30000,crAmt:40000},{dr:"貸倒損失",cr:"売掛金",drAmt:10000,crAmt:0}],exp:"引当金残高30,000円を超える部分10,000円は貸倒損失（費用）で処理します。貸倒引当金30,000円＋貸倒損失10,000円＝売掛金40,000円の消滅です。"},
{id:58,ch:2,themeId:"ch2-2",type:"journal",diff:3,q:"前期に貸し倒れとして処理した売掛金25,000円が現金で回収された。",entries:[{dr:"現金",cr:"償却債権取立益",amt:25000}],exp:"前期に貸し倒れ処理（売掛金を消去）した債権が回収された場合、「償却債権取立益」（収益）で処理します。"},
{id:59,ch:2,themeId:"ch2-2",type:"calc",diff:2,q:"売掛金の期首残高180,000円、当期売上（掛け）500,000円、当期回収額450,000円、売上返品20,000円のとき、期末売掛金残高はいくらですか？",ans:210000,unit:"円",exp:"期末残高＝期首180,000＋売上500,000－回収450,000－返品20,000＝210,000円。"},
{id:60,ch:2,themeId:"ch2-2",type:"calc",diff:2,q:"受取手形の期首残高80,000円、当期発生額150,000円、当期決済額120,000円のとき、期末受取手形残高はいくらですか？",ans:110000,unit:"円",exp:"期末残高＝期首80,000＋発生150,000－決済120,000＝110,000円。"},
];

// Appending ch2-2 remaining + ch2-3 + ch2-4 + ch2-5
window.QUESTIONS.push(
// ch2-2 続き
{id:61,ch:2,themeId:"ch2-2",type:"journal",diff:3,q:"所有する受取手形100,000円を取引銀行で割り引き、割引料2,000円を差し引いた残額が当座預金に入金された。",entries:[{dr:"当座預金",cr:"受取手形",drAmt:98000,crAmt:100000},{dr:"手形売却損",cr:"受取手形",drAmt:2000,crAmt:0}],exp:"手形割引は手形を銀行に売却する処理です。受取手形100,000円が減少し、割引料2,000円を手形売却損（費用）として処理、差額98,000円が当座預金に入ります。"},
{id:62,ch:2,themeId:"ch2-2",type:"journal",diff:2,q:"得意先A社の売掛金のうち60,000円を現金で回収し、残り40,000円は翌月回収となった。",entries:[{dr:"現金",cr:"売掛金",amt:60000}],exp:"回収した60,000円分だけ処理します。現金（資産）増加→借方60,000円、売掛金（資産）減少→貸方60,000円。翌月分40,000円はまだ売掛金に残ります。"},
{id:63,ch:2,themeId:"ch2-2",type:"journal",diff:2,q:"商品200,000円を掛けで販売し、発送費5,000円は現金で支払った。",entries:[{dr:"売掛金",cr:"売上",amt:200000},{dr:"発送費",cr:"現金",amt:5000}],exp:"掛け売上：売掛金200,000円増加（借方）/売上200,000円（貸方）。発送費：発送費（費用）5,000円（借方）/現金5,000円（貸方）。2つの仕訳を行います。"},
{id:64,ch:2,themeId:"ch2-2",type:"journal",diff:3,q:"売掛金100,000円について、得意先から掛け代金の5%の売上割戻しを認め、売掛金から差し引いた。",entries:[{dr:"売上",cr:"売掛金",amt:5000}],exp:"売上割戻し（リベート）は売上の減少として処理します。売上5,000円（100,000×5%）を借方に、売掛金5,000円を貸方に記録します。"},
{id:65,ch:2,themeId:"ch2-2",type:"calc",diff:2,q:"期首売掛金250,000円、掛け売上650,000円、現金回収480,000円、手形回収120,000円、返品30,000円のとき、期末売掛金残高はいくらですか？",ans:270000,unit:"円",exp:"期末残高＝250,000＋650,000－480,000－120,000－30,000＝270,000円。現金回収と手形回収はどちらも売掛金の減少です。"},

// ch2-3 買掛金・支払手形
{id:66,ch:2,themeId:"ch2-3",type:"journal",diff:1,q:"D商店から商品300,000円を仕入れ、代金は掛けとした。",entries:[{dr:"仕入",cr:"買掛金",amt:300000}],exp:"仕入（費用）発生→借方、買掛金（負債）増加→貸方。掛けで仕入れると、後で支払う義務（買掛金）が発生します。"},
{id:67,ch:2,themeId:"ch2-3",type:"journal",diff:1,q:"D商店への買掛金180,000円を現金で支払った。",entries:[{dr:"買掛金",cr:"現金",amt:180000}],exp:"買掛金（負債）減少→借方、現金（資産）減少→貸方。買掛金を支払うと負債が減ります。"},
{id:68,ch:2,themeId:"ch2-3",type:"journal",diff:2,q:"D商店への買掛金250,000円について、約束手形を振り出して支払った。",entries:[{dr:"買掛金",cr:"支払手形",amt:250000}],exp:"買掛金（負債）減少→借方、支払手形（負債）増加→貸方。手形を振り出すと買掛金という負債が支払手形という負債に変わります。"},
{id:69,ch:2,themeId:"ch2-3",type:"journal",diff:2,q:"期日が来た支払手形150,000円が当座預金から引き落とされた。",entries:[{dr:"支払手形",cr:"当座預金",amt:150000}],exp:"支払手形（負債）減少→借方、当座預金（資産）減少→貸方。手形の期日に銀行口座から自動的に引き落とされます。"},
{id:70,ch:2,themeId:"ch2-3",type:"journal",diff:2,q:"仕入れた商品20,000円に品質不良があり、買掛金から返品した。",entries:[{dr:"買掛金",cr:"仕入",amt:20000}],exp:"買掛金（負債）減少→借方、仕入（費用）減少→貸方。仕入返品は仕入の取り消しであり、対応する買掛金も減らします。"},
{id:71,ch:2,themeId:"ch2-3",type:"journal",diff:3,q:"買掛金100,000円を期日前に現金で支払い、2%の仕入割引を受けた。",entries:[{dr:"買掛金",cr:"現金",drAmt:100000,crAmt:98000},{dr:"買掛金",cr:"仕入割引",drAmt:0,crAmt:2000}],exp:"仕入割引は収益です。100,000円の買掛金を支払い、2%（2,000円）の割引を受けるため現金支払いは98,000円。買掛金100,000円減少（借方）、現金98,000円減少（貸方）、仕入割引2,000円（収益・貸方）。"},
{id:72,ch:2,themeId:"ch2-3",type:"journal",diff:2,q:"商品100,000円を仕入れ、引取運賃3,000円は現金で支払い、商品代金は掛けとした。",entries:[{dr:"仕入",cr:"買掛金",drAmt:100000,crAmt:100000},{dr:"仕入",cr:"現金",drAmt:3000,crAmt:3000}],exp:"引取運賃（仕入のための費用）は仕入原価に含めます。仕入合計103,000円（借方）＝買掛金100,000円（貸方）＋現金3,000円（貸方）。"},
{id:73,ch:2,themeId:"ch2-3",type:"calc",diff:2,q:"買掛金の期首残高200,000円、当期仕入（掛け）800,000円、当期支払額750,000円、仕入返品25,000円のとき、期末買掛金残高はいくらですか？",ans:225000,unit:"円",exp:"期末残高＝200,000＋800,000－750,000－25,000＝225,000円。"},
{id:74,ch:2,themeId:"ch2-3",type:"calc",diff:2,q:"支払手形の期首残高120,000円、当期振出額300,000円、当期決済額280,000円のとき、期末残高はいくらですか？",ans:140000,unit:"円",exp:"期末残高＝120,000＋300,000－280,000＝140,000円。"},
{id:75,ch:2,themeId:"ch2-3",type:"journal",diff:3,q:"買掛金200,000円について電子記録債務の発生記録を行った。",entries:[{dr:"買掛金",cr:"電子記録債務",amt:200000}],exp:"電子記録債務（負債）増加→貸方、買掛金（負債）減少→借方。電子記録債務は紙の手形の代わりに電子システムで管理する支払義務です。"},
{id:76,ch:2,themeId:"ch2-3",type:"journal",diff:1,q:"E社に対する買掛金350,000円のうち、200,000円を小切手で支払い、残りは翌月払いとした。",entries:[{dr:"買掛金",cr:"当座預金",amt:200000}],exp:"支払った200,000円分のみ処理します。買掛金（負債）200,000円減少（借方）、当座預金（資産）200,000円減少（貸方）。"},
{id:77,ch:2,themeId:"ch2-3",type:"calc",diff:2,q:"A社の買掛金期首50,000円・当期仕入200,000円・支払150,000円・返品10,000円。B社の買掛金期首30,000円・当期仕入100,000円・支払80,000円。買掛金総残高はいくらですか？",ans:140000,unit:"円",exp:"A社：50,000＋200,000－150,000－10,000＝90,000円。B社：30,000＋100,000－80,000＝50,000円。合計＝140,000円。"},
{id:78,ch:2,themeId:"ch2-3",type:"journal",diff:2,q:"商品400,000円を仕入れた。代金のうち100,000円は前払いしていた前払金と相殺し、残額は掛けとした。",entries:[{dr:"仕入",cr:"前払金",drAmt:400000,crAmt:100000},{dr:"仕入",cr:"買掛金",drAmt:0,crAmt:300000}],exp:"仕入400,000円（借方）＝前払金100,000円の消滅（貸方）＋買掛金300,000円の発生（貸方）。前払金は前払いしていた資産です。"},
{id:79,ch:2,themeId:"ch2-3",type:"journal",diff:2,q:"仕入先F社への買掛金80,000円を、同社への売掛金と相殺することで処理した。",entries:[{dr:"買掛金",cr:"売掛金",amt:80000}],exp:"買掛金（負債）80,000円減少→借方、売掛金（資産）80,000円減少→貸方。同一取引先に売掛金と買掛金がある場合、相殺することができます。"},
{id:80,ch:2,themeId:"ch2-3",type:"calc",diff:3,q:"期末の買掛金残高を求める。期首残高150,000円、仕入（掛）合計600,000円、支払（現金）200,000円、支払（手形）150,000円、支払（小切手）100,000円、返品50,000円。",ans:250000,unit:"円",exp:"期末残高＝150,000＋600,000－200,000－150,000－100,000－50,000＝250,000円。支払方法が違っても買掛金の減少として計算します。"},

// ch2-4 商品売買（三分法）
{id:81,ch:2,themeId:"ch2-4",type:"journal",diff:1,q:"商品500,000円を仕入れ、代金は現金で支払った。（三分法）",entries:[{dr:"仕入",cr:"現金",amt:500000}],exp:"三分法では商品の仕入を「仕入」勘定（費用）で処理します。仕入（費用）発生→借方、現金（資産）減少→貸方。"},
{id:82,ch:2,themeId:"ch2-4",type:"journal",diff:1,q:"商品700,000円を販売し、代金は現金で受け取った。（三分法）",entries:[{dr:"現金",cr:"売上",amt:700000}],exp:"三分法では商品の販売を「売上」勘定（収益）で処理します。現金（資産）増加→借方、売上（収益）発生→貸方。"},
{id:83,ch:2,themeId:"ch2-4",type:"journal",diff:1,q:"商品200,000円を掛けで仕入れた。（三分法）",entries:[{dr:"仕入",cr:"買掛金",amt:200000}],exp:"三分法：仕入（費用）発生→借方、買掛金（負債）増加→貸方。"},
{id:84,ch:2,themeId:"ch2-4",type:"journal",diff:1,q:"商品300,000円を掛けで販売した。（三分法）",entries:[{dr:"売掛金",cr:"売上",amt:300000}],exp:"三分法：売掛金（資産）増加→借方、売上（収益）発生→貸方。"},
{id:85,ch:2,themeId:"ch2-4",type:"journal",diff:2,q:"商品150,000円を掛けで仕入れた。引取運賃5,000円は現金で支払った。",entries:[{dr:"仕入",cr:"買掛金",drAmt:155000,crAmt:150000},{dr:"仕入",cr:"現金",drAmt:0,crAmt:5000}],exp:"引取運賃は仕入原価に含めます。仕入155,000円（借方）＝買掛金150,000円（貸方）＋現金5,000円（貸方）。"},
{id:86,ch:2,themeId:"ch2-4",type:"journal",diff:2,q:"商品250,000円を掛けで販売した。発送費4,000円は現金で支払った。",entries:[{dr:"売掛金",cr:"売上",amt:250000},{dr:"発送費",cr:"現金",amt:4000}],exp:"販売費（発送費）は売上原価に含めません。掛け売上250,000円と発送費4,000円は別々に仕訳します。"},
{id:87,ch:2,themeId:"ch2-4",type:"journal",diff:2,q:"仕入返品：掛けで仕入れた商品のうち30,000円を品質不良で返品した。",entries:[{dr:"買掛金",cr:"仕入",amt:30000}],exp:"仕入返品：買掛金（負債）減少→借方、仕入（費用）減少→貸方。返品すると仕入を取り消します。"},
{id:88,ch:2,themeId:"ch2-4",type:"journal",diff:2,q:"売上返品：掛けで販売した商品のうち25,000円が返品された。",entries:[{dr:"売上",cr:"売掛金",amt:25000}],exp:"売上返品：売上（収益）減少→借方、売掛金（資産）減少→貸方。返品されると売上を取り消します。"},
{id:89,ch:2,themeId:"ch2-4",type:"choice",diff:1,q:"三分法で商品売買を記録するとき使用する3つの勘定科目はどれですか？",opts:["仕入・売上・繰越商品","現金・売掛金・買掛金","仕入・商品・売上","商品・仕入・在庫"],ans:0,exp:"三分法で使う3つの勘定科目は①仕入（費用：商品購入時）②売上（収益：商品販売時）③繰越商品（資産：期末棚卸残高）です。"},
{id:90,ch:2,themeId:"ch2-4",type:"calc",diff:2,q:"売上600,000円、売上原価400,000円のとき、売上総利益はいくらですか？",ans:200000,unit:"円",exp:"売上総利益＝売上－売上原価＝600,000－400,000＝200,000円。売上総利益は「粗利」とも呼ばれます。"},
{id:91,ch:2,themeId:"ch2-4",type:"journal",diff:3,q:"掛け仕入れた商品の代金を期日前に現金支払いし、3,000円の仕入割引を受けた。買掛金残高は103,000円。",entries:[{dr:"買掛金",cr:"現金",drAmt:103000,crAmt:100000},{dr:"買掛金",cr:"仕入割引",drAmt:0,crAmt:3000}],exp:"仕入割引は収益。買掛金103,000円（借方）＝現金100,000円（貸方）＋仕入割引3,000円（貸方）。"},
{id:92,ch:2,themeId:"ch2-4",type:"journal",diff:3,q:"得意先への掛け売上代金100,000円を期日前に回収し、2,000円の売上割引を与えた。",entries:[{dr:"現金",cr:"売掛金",drAmt:98000,crAmt:100000},{dr:"売上割引",cr:"売掛金",drAmt:2000,crAmt:0}],exp:"売上割引は費用。現金98,000円（借方）＋売上割引2,000円（費用・借方）＝売掛金100,000円（貸方）。"},
{id:93,ch:2,themeId:"ch2-4",type:"journal",diff:3,q:"仕入先から仕入割戻しとして5,000円が認められ、買掛金から差し引かれた。",entries:[{dr:"買掛金",cr:"仕入",amt:5000}],exp:"仕入割戻しは仕入の減少として処理します。買掛金（負債）減少→借方、仕入（費用）減少→貸方。"},
{id:94,ch:2,themeId:"ch2-4",type:"journal",diff:3,q:"得意先への販売について売上割戻し8,000円を認め、売掛金から差し引いた。",entries:[{dr:"売上",cr:"売掛金",amt:8000}],exp:"売上割戻しは売上の減少として処理します。売上（収益）減少→借方、売掛金（資産）減少→貸方。"},
{id:95,ch:2,themeId:"ch2-4",type:"calc",diff:2,q:"総売上750,000円、売上返品30,000円、売上割戻し20,000円のとき、純売上高はいくらですか？",ans:700000,unit:"円",exp:"純売上高＝総売上－返品－割戻し＝750,000－30,000－20,000＝700,000円。"},
{id:96,ch:2,themeId:"ch2-4",type:"calc",diff:2,q:"期首繰越商品50,000円、当期純仕入高400,000円、期末繰越商品30,000円のとき、売上原価はいくらですか？",ans:420000,unit:"円",exp:"売上原価＝期首繰越商品＋純仕入高－期末繰越商品＝50,000＋400,000－30,000＝420,000円。"},
{id:97,ch:2,themeId:"ch2-4",type:"calc",diff:2,q:"売上高500,000円、売上原価350,000円のとき、売上総利益率はいくらですか？（小数点以下切り捨て）",ans:30,unit:"%",exp:"売上総利益率＝（売上高－売上原価）÷売上高×100＝150,000÷500,000×100＝30%。"},
{id:98,ch:2,themeId:"ch2-4",type:"choice",diff:1,q:"三分法において、期末に商品の棚卸しを行い残高を計上する勘定科目はどれですか？",opts:["繰越商品","商品","在庫品","棚卸商品"],ans:0,exp:"三分法では期末棚卸高を「繰越商品」（資産）勘定に計上します。翌期首に仕入勘定に振り替えます。"},
{id:99,ch:2,themeId:"ch2-4",type:"choice",diff:2,q:"三分法での売上原価の計算式として正しいものはどれですか？",opts:["期首繰越商品＋当期仕入高－期末繰越商品","当期仕入高－期末繰越商品","期首繰越商品＋当期仕入高","当期売上高－売上総利益"],ans:0,exp:"売上原価＝期首繰越商品＋当期仕入高－期末繰越商品。これは「いくらの商品を販売したか」を表す計算式です。"},
{id:100,ch:2,themeId:"ch2-4",type:"calc",diff:3,q:"次のデータから売上総利益を求めなさい。売上高800,000円、期首繰越商品60,000円、仕入高550,000円、仕入返品20,000円、期末繰越商品40,000円。",ans:250000,unit:"円",exp:"純仕入高＝550,000－20,000＝530,000円。売上原価＝60,000＋530,000－40,000＝550,000円。売上総利益＝800,000－550,000＝250,000円。"},

// ch2-5 固定資産の取得・減価償却・売却
{id:101,ch:2,themeId:"ch2-5",type:"journal",diff:1,q:"建物2,000,000円を購入し、代金は現金で支払った。",entries:[{dr:"建物",cr:"現金",amt:2000000}],exp:"建物（資産）増加→借方、現金（資産）減少→貸方。固定資産を購入した場合は取得価額（購入代金＋附随費用）で資産に計上します。"},
{id:102,ch:2,themeId:"ch2-5",type:"journal",diff:2,q:"備品300,000円を購入し、設置費用10,000円とあわせて現金で支払った。",entries:[{dr:"備品",cr:"現金",amt:310000}],exp:"設置費用は備品の取得原価に含めます。備品（資産）310,000円増加→借方、現金310,000円減少→貸方。"},
{id:103,ch:2,themeId:"ch2-5",type:"journal",diff:1,q:"車両1,500,000円を購入し、代金は小切手で支払った。",entries:[{dr:"車両運搬具",cr:"当座預金",amt:1500000}],exp:"車両運搬具（資産）増加→借方、当座預金（資産）減少→貸方。小切手の振り出しは当座預金の減少です。"},
{id:104,ch:2,themeId:"ch2-5",type:"journal",diff:1,q:"土地5,000,000円を購入し、代金は翌月払いとした。",entries:[{dr:"土地",cr:"未払金",amt:5000000}],exp:"土地（資産）増加→借方、未払金（負債）増加→貸方。固定資産の購入代金の未払いは「未払金」で処理します（買掛金は商品の未払いに使います）。"},
{id:105,ch:2,themeId:"ch2-5",type:"calc",diff:2,q:"取得原価600,000円、残存価額0円、耐用年数5年の備品の定額法による1年間の減価償却費はいくらですか？",ans:120000,unit:"円",exp:"定額法の減価償却費＝（取得原価－残存価額）÷耐用年数＝（600,000－0）÷5＝120,000円。毎年同額を費用として計上します。"},
{id:106,ch:2,themeId:"ch2-5",type:"journal",diff:2,q:"備品（取得原価500,000円、残存価額0円、耐用年数5年）の当期分の減価償却を直接法で行った。",entries:[{dr:"減価償却費",cr:"備品",amt:100000}],exp:"定額法：500,000÷5＝100,000円。直接法は資産から直接差し引きます。減価償却費（費用）100,000円（借方）、備品（資産）100,000円減少（貸方）。"},
{id:107,ch:2,themeId:"ch2-5",type:"journal",diff:2,q:"建物（取得原価3,000,000円、残存価額0円、耐用年数30年）の当期分の減価償却を間接法で行った。",entries:[{dr:"減価償却費",cr:"減価償却累計額",amt:100000}],exp:"定額法：3,000,000÷30＝100,000円。間接法では資産を直接減らさず「減価償却累計額」（資産のマイナス）で記録します。"},
{id:108,ch:2,themeId:"ch2-5",type:"calc",diff:2,q:"取得原価800,000円の備品を3年間使用した。定額法・残存価額0円・耐用年数8年の場合、3年後の帳簿価額はいくらですか？",ans:500000,unit:"円",exp:"年間減価償却費＝800,000÷8＝100,000円。3年分の累計償却額＝300,000円。帳簿価額＝800,000－300,000＝500,000円。"},
{id:109,ch:2,themeId:"ch2-5",type:"journal",diff:3,q:"備品（取得原価400,000円、減価償却累計額240,000円）を180,000円で売却し、現金で受け取った。（間接法）",entries:[{dr:"現金",cr:"備品",drAmt:180000,crAmt:400000},{dr:"減価償却累計額",cr:"固定資産売却益",drAmt:240000,crAmt:20000}],exp:"帳簿価額＝400,000－240,000＝160,000円。売却価格180,000円＞帳簿価額160,000円なので売却益20,000円。現金180,000円（借方）＋減価償却累計額240,000円（借方）＝備品400,000円（貸方）＋固定資産売却益20,000円（貸方）。"},
{id:110,ch:2,themeId:"ch2-5",type:"journal",diff:3,q:"車両（取得原価600,000円、減価償却累計額350,000円）を200,000円で売却し、現金で受け取った。（間接法）",entries:[{dr:"現金",cr:"車両運搬具",drAmt:200000,crAmt:600000},{dr:"減価償却累計額",cr:"固定資産売却損",drAmt:350000,crAmt:0},{dr:"固定資産売却損",cr:"車両運搬具",drAmt:50000,crAmt:0}],exp:"帳簿価額＝600,000－350,000＝250,000円。売却価格200,000円＜帳簿価額250,000円なので売却損50,000円。"},
{id:111,ch:2,themeId:"ch2-5",type:"calc",diff:3,q:"7月1日（期首4月1日）に取得した備品200,000円、残存価額0円、耐用年数4年。当期の減価償却費（月割り）はいくらですか？",ans:25000,unit:"円",exp:"年間償却費＝200,000÷4＝50,000円。7月から3月の9か月分＝50,000×9/12＝37,500円。ただしこの問題は（200,000÷4）×（9/12）＝37,500円…再確認：取得7月1日、期末3月31日で9ヶ月。答えは37,500円。"},
{id:112,ch:2,themeId:"ch2-5",type:"calc",diff:2,q:"取得原価1,200,000円、耐用年数10年、残存価額0円の建物を期首に購入。2年目末の帳簿価額はいくらですか？",ans:960000,unit:"円",exp:"年間償却費＝1,200,000÷10＝120,000円。2年分償却累計＝240,000円。帳簿価額＝1,200,000－240,000＝960,000円。"},
{id:113,ch:2,themeId:"ch2-5",type:"choice",diff:2,q:"残存価額の説明として正しいものはどれですか？",opts:["耐用年数経過後の見積もり処分価額","取得にかかった費用の合計","1年間の減価償却費の金額","固定資産を売却した価格"],ans:0,exp:"残存価額は耐用年数終了時に残ると見込まれる価値（スクラップ価値など）です。現在の日商簿記3級では残存価額をゼロとして計算することが主流です。"},
{id:114,ch:2,themeId:"ch2-5",type:"choice",diff:2,q:"固定資産の取得原価に含めるものとして正しいものはどれですか？",opts:["購入手数料や登記費用などの附随費用","取得後の修繕費","固定資産の保険料","減価償却費"],ans:0,exp:"固定資産の取得原価には、購入代金だけでなく購入手数料・登記費用・引取運賃など、その資産を使用できる状態にするまでにかかったすべての費用（附随費用）を含めます。"},
{id:115,ch:2,themeId:"ch2-5",type:"choice",diff:1,q:"定額法の説明として正しいものはどれですか？",opts:["毎年同額の減価償却費を計上する方法","初年度に多く計上する方法","残存価額が多いほど償却額が大きい方法","取得価額の一定割合を毎年計上する方法"],ans:0,exp:"定額法は毎年同じ金額（取得原価÷耐用年数）を減価償却費として計上する方法です。簿記3級では定額法が中心です。"},
{id:116,ch:2,themeId:"ch2-5",type:"choice",diff:2,q:"間接法と直接法の違いとして正しいものはどれですか？",opts:["間接法は減価償却累計額勘定を使い、直接法は資産を直接減額する","間接法は毎年2回計上し、直接法は1回だけ","間接法は取得原価を毎年増やす","直接法は減価償却累計額を使う"],ans:0,exp:"間接法は「減価償却累計額」勘定で資産のマイナスを別途管理します。直接法は資産の金額を直接減額します。間接法の方が取得原価と累計償却額が別々に分かり情報量が多いです。"},
{id:117,ch:2,themeId:"ch2-5",type:"choice",diff:2,q:"貸借対照表における「減価償却累計額」の表示方法として正しいものはどれですか？",opts:["固定資産の金額から控除（マイナス）表示","固定資産の金額に加算","負債の部に計上","費用として損益計算書に計上"],ans:0,exp:"減価償却累計額は貸借対照表の資産の部で、対応する固定資産の金額から差し引いて表示します（間接控除法）。"},
{id:118,ch:2,themeId:"ch2-5",type:"calc",diff:2,q:"取得原価500,000円、残存価額0円、耐用年数5年の備品の4年目末の帳簿価額はいくらですか？",ans:100000,unit:"円",exp:"年間償却費＝500,000÷5＝100,000円。4年分累計＝400,000円。帳簿価額＝500,000－400,000＝100,000円。"},
{id:119,ch:2,themeId:"ch2-5",type:"journal",diff:3,q:"完全に減価償却された備品（取得原価200,000円、減価償却累計額200,000円）を廃棄した。",entries:[{dr:"減価償却累計額",cr:"備品",amt:200000}],exp:"帳簿価額0円の資産を廃棄。減価償却累計額200,000円（借方）、備品200,000円（貸方）。廃棄損はゼロです。"},
{id:120,ch:2,themeId:"ch2-5",type:"journal",diff:3,q:"建物（取得原価2,000,000円、減価償却累計額800,000円）を1,100,000円で売却し、代金は翌月受取とした。",entries:[{dr:"未収金",cr:"建物",drAmt:1100000,crAmt:2000000},{dr:"減価償却累計額",cr:"固定資産売却益",drAmt:800000,crAmt:0},{dr:"固定資産売却損",cr:"建物",drAmt:100000,crAmt:0}],exp:"帳簿価額＝2,000,000－800,000＝1,200,000円。売却価格1,100,000円＜帳簿価額なので売却損100,000円。売却代金の未収は「未収金」（資産）で処理。"}
);

window.QUESTIONS.push(
// ch2-6 貸付金・借入金
{id:121,ch:2,themeId:"ch2-6",type:"journal",diff:1,q:"得意先に現金200,000円を貸し付けた。",entries:[{dr:"貸付金",cr:"現金",amt:200000}],exp:"貸付金（資産）増加→借方、現金（資産）減少→貸方。お金を貸すと「返してもらえる権利」（貸付金）が生じます。"},
{id:122,ch:2,themeId:"ch2-6",type:"journal",diff:1,q:"貸付金150,000円が期日を迎え、現金で回収した。",entries:[{dr:"現金",cr:"貸付金",amt:150000}],exp:"現金（資産）増加→借方、貸付金（資産）減少→貸方。貸したお金が戻ってきたため貸付金という資産が現金という資産に変わります。"},
{id:123,ch:2,themeId:"ch2-6",type:"journal",diff:1,q:"貸付金の利息5,000円を現金で受け取った。",entries:[{dr:"現金",cr:"受取利息",amt:5000}],exp:"現金（資産）増加→借方、受取利息（収益）発生→貸方。利息収入は「受取利息」（収益）で処理します。"},
{id:124,ch:2,themeId:"ch2-6",type:"journal",diff:2,q:"貸付金100,000円と利息2,000円をあわせて現金で受け取った。",entries:[{dr:"現金",cr:"貸付金",drAmt:102000,crAmt:100000},{dr:"現金",cr:"受取利息",drAmt:0,crAmt:2000}],exp:"現金102,000円（借方）＝貸付金100,000円（貸方）＋受取利息2,000円（貸方）。元金と利息を分けて処理します。"},
{id:125,ch:2,themeId:"ch2-6",type:"journal",diff:1,q:"銀行から現金500,000円を借り入れた。",entries:[{dr:"現金",cr:"借入金",amt:500000}],exp:"現金（資産）増加→借方、借入金（負債）増加→貸方。お金を借りると「返さなければならない義務」（借入金）が生じます。"},
{id:126,ch:2,themeId:"ch2-6",type:"journal",diff:1,q:"借入金300,000円を期日に現金で返済した。",entries:[{dr:"借入金",cr:"現金",amt:300000}],exp:"借入金（負債）減少→借方、現金（資産）減少→貸方。借金を返すと負債（借入金）が減ります。"},
{id:127,ch:2,themeId:"ch2-6",type:"journal",diff:1,q:"借入金の利息8,000円を現金で支払った。",entries:[{dr:"支払利息",cr:"現金",amt:8000}],exp:"支払利息（費用）発生→借方、現金（資産）減少→貸方。借入金の利息は「支払利息」（費用）で処理します。"},
{id:128,ch:2,themeId:"ch2-6",type:"journal",diff:2,q:"借入金200,000円と利息4,000円をあわせて現金で返済した。",entries:[{dr:"借入金",cr:"現金",drAmt:200000,crAmt:204000},{dr:"支払利息",cr:"現金",drAmt:4000,crAmt:0}],exp:"借入金200,000円（借方）＋支払利息4,000円（借方）＝現金204,000円（貸方）。元金と利息を分けて処理します。"},
{id:129,ch:2,themeId:"ch2-6",type:"calc",diff:2,q:"元金500,000円、年利率2%、貸付期間1年の場合、受取利息はいくらですか？",ans:10000,unit:"円",exp:"受取利息＝元金×年利率×期間＝500,000×2%×1＝10,000円。"},
{id:130,ch:2,themeId:"ch2-6",type:"calc",diff:2,q:"元金300,000円、年利率3%、借入期間6か月の場合、支払利息はいくらですか？",ans:4500,unit:"円",exp:"支払利息＝300,000×3%×6/12＝4,500円。月割り計算では年利÷12×月数で計算します。"},
{id:131,ch:2,themeId:"ch2-6",type:"calc",diff:2,q:"貸付金の期首残高250,000円、当期貸付200,000円、当期回収300,000円のとき、期末残高はいくらですか？",ans:150000,unit:"円",exp:"期末残高＝250,000＋200,000－300,000＝150,000円。"},
{id:132,ch:2,themeId:"ch2-6",type:"calc",diff:2,q:"借入金の期首残高400,000円、当期借入100,000円、当期返済200,000円のとき、期末残高はいくらですか？",ans:300000,unit:"円",exp:"期末残高＝400,000＋100,000－200,000＝300,000円。"},
{id:133,ch:2,themeId:"ch2-6",type:"choice",diff:2,q:"短期借入金と長期借入金の区分の基準はどれですか？",opts:["返済期限が1年以内かどうか","借入金額が100万円以上かどうか","銀行からの借入かどうか","担保があるかどうか"],ans:0,exp:"返済期限が1年以内のものを短期借入金（流動負債）、1年超のものを長期借入金（固定負債）に区分します。"},
{id:134,ch:2,themeId:"ch2-6",type:"journal",diff:2,q:"従業員に現金50,000円を貸し付けた（立替金ではなく貸付）。",entries:[{dr:"貸付金",cr:"現金",amt:50000}],exp:"従業員への貸付も「貸付金」（資産）で処理します。現金（資産）減少→貸方、貸付金（資産）増加→借方。"},
{id:135,ch:2,themeId:"ch2-6",type:"journal",diff:2,q:"役員から事業資金として現金1,000,000円を借り入れた。",entries:[{dr:"現金",cr:"借入金",amt:1000000}],exp:"役員からの借入も「借入金」（負債）で処理します。現金（資産）増加→借方、借入金（負債）増加→貸方。"},

// ch2-7 資本金・引出金
{id:136,ch:2,themeId:"ch2-7",type:"journal",diff:1,q:"事業を始めるにあたり、現金1,000,000円を出資した。",entries:[{dr:"現金",cr:"資本金",amt:1000000}],exp:"現金（資産）増加→借方、資本金（純資産）増加→貸方。事業開始時の元手（出資）は「資本金」として処理します。"},
{id:137,ch:2,themeId:"ch2-7",type:"journal",diff:2,q:"事業主が追加で現金300,000円を出資した。",entries:[{dr:"現金",cr:"資本金",amt:300000}],exp:"追加出資も資本金の増加です。現金（資産）増加→借方、資本金（純資産）増加→貸方。"},
{id:138,ch:2,themeId:"ch2-7",type:"journal",diff:1,q:"事業主が私用のため、事業の現金50,000円を引き出した。",entries:[{dr:"引出金",cr:"現金",amt:50000}],exp:"引出金（純資産のマイナス）増加→借方、現金（資産）減少→貸方。店主の私的引き出しは「引出金」で処理します。"},
{id:139,ch:2,themeId:"ch2-7",type:"journal",diff:2,q:"事業主が私用のため、事業の商品20,000円（原価）を引き出した。",entries:[{dr:"引出金",cr:"仕入",amt:20000}],exp:"商品を引き出した場合も引出金で処理します。引出金（借方）、仕入（費用）の減少（貸方）。"},
{id:140,ch:2,themeId:"ch2-7",type:"journal",diff:2,q:"決算において、引出金80,000円を資本金に振り替えた。",entries:[{dr:"資本金",cr:"引出金",amt:80000}],exp:"決算時に引出金残高を資本金から差し引きます。資本金（純資産）減少→借方、引出金の消去→貸方。"},
{id:141,ch:2,themeId:"ch2-7",type:"choice",diff:1,q:"資本金の説明として正しいものはどれですか？",opts:["事業主が事業に出資した元手","事業が銀行から借りたお金","事業主が毎月受け取る給料","商品の売上から得た利益"],ans:0,exp:"資本金は事業主が事業を始める（または継続する）ために出資した元手のことです。純資産の主要な構成要素です。"},
{id:142,ch:2,themeId:"ch2-7",type:"choice",diff:1,q:"引出金の説明として正しいものはどれですか？",opts:["事業主が私的に資産を引き出した金額","事業から外部に支払った費用","銀行から引き出した現金","税金の支払い額"],ans:0,exp:"引出金は個人事業主が事業の財産を私的目的で引き出したときに使う勘定科目です。決算時に資本金から差し引かれます。"},
{id:143,ch:2,themeId:"ch2-7",type:"calc",diff:2,q:"期首資本金800,000円、当期追加出資200,000円、当期引出金60,000円、当期純利益150,000円のとき、期末資本金残高はいくらですか？",ans:1090000,unit:"円",exp:"期末資本金＝期首800,000＋追加出資200,000－引出金60,000＋純利益150,000＝1,090,000円。"},
{id:144,ch:2,themeId:"ch2-7",type:"journal",diff:2,q:"事業主が自己所有の建物（時価500,000円）を事業に出資した。",entries:[{dr:"建物",cr:"資本金",amt:500000}],exp:"現金以外の資産で出資する場合も「資本金」（純資産）の増加として処理します。建物（資産）増加→借方、資本金（純資産）増加→貸方。"},
{id:145,ch:2,themeId:"ch2-7",type:"calc",diff:2,q:"期首資本金1,000,000円、引出金100,000円、当期純利益200,000円のとき、期末の純資産額はいくらですか？",ans:1100000,unit:"円",exp:"期末純資産＝1,000,000－100,000＋200,000＝1,100,000円。"},

// ch2-8 給料・租税公課
{id:146,ch:2,themeId:"ch2-8",type:"journal",diff:1,q:"従業員の給料300,000円を現金で支払った。",entries:[{dr:"給料",cr:"現金",amt:300000}],exp:"給料（費用）発生→借方、現金（資産）減少→貸方。"},
{id:147,ch:2,themeId:"ch2-8",type:"journal",diff:2,q:"給料総額250,000円から源泉所得税15,000円を控除し、残額を現金で支払った。",entries:[{dr:"給料",cr:"現金",drAmt:250000,crAmt:235000},{dr:"給料",cr:"所得税預り金",drAmt:0,crAmt:15000}],exp:"給料250,000円（借方）＝現金235,000円（貸方）＋所得税預り金15,000円（貸方）。会社は税務署に代わって従業員の所得税を預かります。"},
{id:148,ch:2,themeId:"ch2-8",type:"journal",diff:2,q:"源泉徴収した所得税20,000円を税務署に現金で納付した。",entries:[{dr:"所得税預り金",cr:"現金",amt:20000}],exp:"所得税預り金（負債）減少→借方、現金（資産）減少→貸方。預かっていた税金を税務署に納めます。"},
{id:149,ch:2,themeId:"ch2-8",type:"journal",diff:3,q:"社会保険料40,000円を支払った。うち従業員負担分20,000円は給料から控除済み、会社負担分20,000円は法定福利費とする。",entries:[{dr:"法定福利費",cr:"現金",drAmt:20000,crAmt:40000},{dr:"預り金",cr:"現金",drAmt:20000,crAmt:0}],exp:"会社負担分20,000円は法定福利費（費用）、従業員から預かった分20,000円は預り金（負債）の減少として処理します。"},
{id:150,ch:2,themeId:"ch2-8",type:"journal",diff:2,q:"固定資産税60,000円を現金で支払った。",entries:[{dr:"租税公課",cr:"現金",amt:60000}],exp:"固定資産税・印紙税・自動車税などの税金は「租税公課」（費用）で処理します。租税公課（費用）発生→借方、現金（資産）減少→貸方。"},
{id:151,ch:2,themeId:"ch2-8",type:"journal",diff:2,q:"収入印紙3,000円分を現金で購入した。",entries:[{dr:"租税公課",cr:"現金",amt:3000}],exp:"収入印紙は租税公課（費用）で処理します。購入時に費用として計上します。"},
{id:152,ch:2,themeId:"ch2-8",type:"journal",diff:1,q:"電気代・ガス代・水道代として30,000円を現金で支払った。",entries:[{dr:"水道光熱費",cr:"現金",amt:30000}],exp:"電気・ガス・水道の料金は「水道光熱費」（費用）で処理します。"},
{id:153,ch:2,themeId:"ch2-8",type:"journal",diff:1,q:"電話代・インターネット料金として15,000円を普通預金から支払った。",entries:[{dr:"通信費",cr:"普通預金",amt:15000}],exp:"電話・郵便・インターネット等の費用は「通信費」（費用）で処理します。"},
{id:154,ch:2,themeId:"ch2-8",type:"journal",diff:1,q:"出張旅費として新幹線代・宿泊費あわせて80,000円を現金で支払った。",entries:[{dr:"旅費交通費",cr:"現金",amt:80000}],exp:"交通費・旅費・出張費は「旅費交通費」（費用）で処理します。"},
{id:155,ch:2,themeId:"ch2-8",type:"journal",diff:2,q:"事務用品（消耗品）を12,000円分購入し、当期中にすべて使用した。代金は現金。",entries:[{dr:"消耗品費",cr:"現金",amt:12000}],exp:"当期中に使用した消耗品は「消耗品費」（費用）として処理します。消耗品費（費用）発生→借方、現金（資産）減少→貸方。"},
{id:156,ch:2,themeId:"ch2-8",type:"journal",diff:2,q:"火災保険料1年分120,000円を現金で支払った（期中の処理）。",entries:[{dr:"支払保険料",cr:"現金",amt:120000}],exp:"保険料の支払いは「支払保険料」（費用）で処理します。期中はすべて費用として計上し、期末に前払い分を調整します。"},
{id:157,ch:2,themeId:"ch2-8",type:"journal",diff:1,q:"新聞広告代50,000円を現金で支払った。",entries:[{dr:"広告宣伝費",cr:"現金",amt:50000}],exp:"広告・宣伝・PR費用は「広告宣伝費」（費用）で処理します。"},
{id:158,ch:2,themeId:"ch2-8",type:"journal",diff:1,q:"事務所の家賃80,000円を現金で支払った。",entries:[{dr:"支払家賃",cr:"現金",amt:80000}],exp:"事務所・店舗の賃借料は「支払家賃」（費用）で処理します。"},
{id:159,ch:2,themeId:"ch2-8",type:"calc",diff:2,q:"給料総額200,000円、源泉所得税10,000円、社会保険料（本人負担）8,000円のとき、手取り額はいくらですか？",ans:182000,unit:"円",exp:"手取り額＝200,000－10,000－8,000＝182,000円。源泉所得税と社会保険料の従業員負担分を差し引いた金額が実際の受取額です。"},
{id:160,ch:2,themeId:"ch2-8",type:"calc",diff:2,q:"給料300,000円、水道光熱費25,000円、通信費18,000円、支払家賃100,000円の合計費用はいくらですか？",ans:443000,unit:"円",exp:"費用合計＝300,000＋25,000＋18,000＋100,000＝443,000円。"},

// ch2-9 前払い・前受け・未払い・未収の処理
{id:161,ch:2,themeId:"ch2-9",type:"journal",diff:2,q:"4月1日に保険料1年分（4月〜翌3月）を現金120,000円で支払った。（期中の処理）",entries:[{dr:"支払保険料",cr:"現金",amt:120000}],exp:"期中は支払った全額を費用として記録します。支払保険料（費用）120,000円（借方）、現金（資産）減少（貸方）。"},
{id:162,ch:2,themeId:"ch2-9",type:"journal",diff:2,q:"決算（3月31日）において、上記保険料のうち翌期分3か月分を前払費用に振り替えた。",entries:[{dr:"前払費用",cr:"支払保険料",amt:30000}],exp:"翌期分（4〜6月）の3か月分＝120,000×3/12＝30,000円を前払費用（資産）に振り替えます。前払費用（資産）増加→借方、支払保険料（費用）減少→貸方。"},
{id:163,ch:2,themeId:"ch2-9",type:"choice",diff:1,q:"前払費用の分類として正しいものはどれですか？",opts:["資産","負債","費用","収益"],ans:0,exp:"前払費用は「まだサービスを受けていないのに代金を先払いした分」で、将来の費用の前払いです。翌期以降に費用になるため、資産として処理します。"},
{id:164,ch:2,themeId:"ch2-9",type:"journal",diff:2,q:"4月1日に店舗を貸し出し、1年分の家賃240,000円を現金で受け取った。（期中の処理）",entries:[{dr:"現金",cr:"前受収益",amt:240000}],exp:"まだ提供していないサービス分は「前受収益」（負債）として処理します。現金（資産）増加→借方、前受収益（負債）増加→貸方。"},
{id:165,ch:2,themeId:"ch2-9",type:"journal",diff:2,q:"決算（3月31日）において、前受家賃のうち当期分9か月分を受取家賃に振り替えた。",entries:[{dr:"前受収益",cr:"受取家賃",amt:180000}],exp:"当期分（4〜12月）の9か月＝240,000×9/12＝180,000円を収益に計上。前受収益（負債）減少→借方、受取家賃（収益）発生→貸方。"},
{id:166,ch:2,themeId:"ch2-9",type:"choice",diff:1,q:"前受収益の分類として正しいものはどれですか？",opts:["負債","資産","収益","費用"],ans:0,exp:"前受収益は「サービスを提供する前にもらった収益」で、将来サービスを提供する義務があるため負債に分類されます。"},
{id:167,ch:2,themeId:"ch2-9",type:"journal",diff:2,q:"決算において、当期分の未払給料50,000円を計上した。",entries:[{dr:"給料",cr:"未払費用",amt:50000}],exp:"未払費用（負債）発生→貸方、給料（費用）発生→借方。当期に発生したが未払いの費用は、決算で計上が必要です。"},
{id:168,ch:2,themeId:"ch2-9",type:"journal",diff:2,q:"翌期首において、前期末に計上した未払給料50,000円を現金で支払った。",entries:[{dr:"未払費用",cr:"現金",amt:50000}],exp:"未払費用（負債）減少→借方、現金（資産）減少→貸方。前期末に計上した未払い分を翌期に支払います。"},
{id:169,ch:2,themeId:"ch2-9",type:"journal",diff:2,q:"決算において、貸付金の未収利息8,000円を計上した。",entries:[{dr:"未収収益",cr:"受取利息",amt:8000}],exp:"未収収益（資産）増加→借方、受取利息（収益）発生→貸方。当期に発生したが未収の収益を計上します。"},
{id:170,ch:2,themeId:"ch2-9",type:"journal",diff:2,q:"翌期首において、前期末に計上した未収利息8,000円を現金で受け取った。",entries:[{dr:"現金",cr:"未収収益",amt:8000}],exp:"現金（資産）増加→借方、未収収益（資産）減少→貸方。前期末に計上した未収分を翌期に回収します。"},
{id:171,ch:2,themeId:"ch2-9",type:"calc",diff:2,q:"10月1日に保険料1年分120,000円を支払った（決算は3月31日）。期末の前払保険料はいくらですか？",ans:60000,unit:"円",exp:"前払い分＝翌期4〜9月の6か月分＝120,000×6/12＝60,000円。"},
{id:172,ch:2,themeId:"ch2-9",type:"calc",diff:2,q:"1月1日に家賃6か月分を180,000円前受けした（決算は3月31日）。期末の前受収益はいくらですか？",ans:90000,unit:"円",exp:"前受分＝翌期4〜6月の3か月分＝180,000×3/6＝90,000円。"},
{id:173,ch:2,themeId:"ch2-9",type:"calc",diff:2,q:"給料は月末締め翌月10日払い。月給30,000円のとき、決算（3月31日）での未払費用はいくらですか？",ans:30000,unit:"円",exp:"3月分の給料は翌4月10日に支払われるため、3月31日時点で未払費用30,000円が生じています。"},
{id:174,ch:2,themeId:"ch2-9",type:"choice",diff:2,q:"次の4つを正しく分類した組み合わせはどれですか？【前払費用・前受収益・未払費用・未収収益】",opts:["資産・負債・負債・資産","負債・資産・資産・負債","資産・資産・負債・負債","負債・負債・資産・資産"],ans:0,exp:"前払費用＝資産、前受収益＝負債、未払費用＝負債、未収収益＝資産。「前払い・未収」は資産、「前受け・未払い」は負債と覚えましょう。"},
{id:175,ch:2,themeId:"ch2-9",type:"choice",diff:3,q:"翌期首の再振替仕訳（逆仕訳）として正しいものはどれですか？（前期末に未払費用30,000円を計上した場合）",opts:["（借）未払費用30,000 （貸）給料30,000","（借）給料30,000 （貸）未払費用30,000","（借）現金30,000 （貸）未払費用30,000","再振替仕訳は不要"],ans:0,exp:"前期末に（借）給料/（貸）未払費用と記録したものを、翌期首に逆仕訳して（借）未払費用/（貸）給料とします。これにより翌期の費用処理が自動的に正しくなります。"},

// ch2-10 貸倒引当金
{id:176,ch:2,themeId:"ch2-10",type:"journal",diff:2,q:"売掛金残高500,000円に対して2%の貸倒引当金を設定した。（引当金残高なし）",entries:[{dr:"貸倒引当金繰入",cr:"貸倒引当金",amt:10000}],exp:"設定額＝500,000×2%＝10,000円。貸倒引当金繰入（費用）増加→借方、貸倒引当金（資産のマイナス）増加→貸方。"},
{id:177,ch:2,themeId:"ch2-10",type:"journal",diff:2,q:"売掛金30,000円が貸し倒れた。貸倒引当金の残高は40,000円ある。",entries:[{dr:"貸倒引当金",cr:"売掛金",amt:30000}],exp:"引当金残高（40,000円）が貸倒額（30,000円）以上なので、貸倒引当金の範囲内で処理。貸倒引当金（資産のマイナス）減少→借方、売掛金（資産）減少→貸方。"},
{id:178,ch:2,themeId:"ch2-10",type:"journal",diff:3,q:"売掛金50,000円が貸し倒れた。貸倒引当金の残高は30,000円ある。",entries:[{dr:"貸倒引当金",cr:"売掛金",drAmt:30000,crAmt:50000},{dr:"貸倒損失",cr:"売掛金",drAmt:20000,crAmt:0}],exp:"引当金30,000円を超える20,000円は貸倒損失（費用）で処理。貸倒引当金30,000円（借方）＋貸倒損失20,000円（借方）＝売掛金50,000円（貸方）。"},
{id:179,ch:2,themeId:"ch2-10",type:"journal",diff:3,q:"当期に貸し倒れとして処理した売掛金15,000円が当期中に現金で回収された。",entries:[{dr:"現金",cr:"貸倒引当金",amt:15000}],exp:"当期中の回収は貸倒引当金を戻します。現金（資産）増加→借方、貸倒引当金（資産のマイナス）減少→貸方。"},
{id:180,ch:2,themeId:"ch2-10",type:"journal",diff:3,q:"前期に貸し倒れとして処理した売掛金20,000円が当期に現金で回収された。",entries:[{dr:"現金",cr:"償却債権取立益",amt:20000}],exp:"前期に売掛金を消去済みなので、当期の回収は「償却債権取立益」（収益）で処理します。現金（資産）増加→借方、償却債権取立益（収益）発生→貸方。"},
{id:181,ch:2,themeId:"ch2-10",type:"calc",diff:2,q:"売掛金残高600,000円、受取手形残高200,000円に対して1%の貸倒引当金を設定する場合の繰入額はいくらですか？",ans:8000,unit:"円",exp:"繰入額＝（600,000＋200,000）×1%＝8,000円。売掛金と受取手形の合計に引当率を掛けます。"},
{id:182,ch:2,themeId:"ch2-10",type:"calc",diff:2,q:"期末売掛金400,000円、引当率2%、既存の貸倒引当金残高3,000円のとき、追加繰入額はいくらですか？",ans:5000,unit:"円",exp:"必要額＝400,000×2%＝8,000円。追加繰入額＝必要額8,000－既存3,000＝5,000円（差額補充法）。"},
{id:183,ch:2,themeId:"ch2-10",type:"choice",diff:1,q:"貸倒引当金の説明として正しいものはどれですか？",opts:["将来の貸倒れ損失に備えて設定する引当金","現在すでに貸し倒れた損失","銀行に預けている担保","売掛金の割引額"],ans:0,exp:"貸倒引当金は、将来売掛金・受取手形などが回収不能になる（貸し倒れ）リスクに備えて、あらかじめ設定する評価性引当金です。"},
{id:184,ch:2,themeId:"ch2-10",type:"choice",diff:2,q:"貸借対照表における貸倒引当金の表示として正しいものはどれですか？",opts:["売掛金等の資産から控除して表示","負債の部に表示","純資産の部に表示","費用として損益計算書に計上"],ans:0,exp:"貸倒引当金は、対応する売掛金・受取手形などの資産の金額から直接差し引いて（控除して）表示します（間接控除法）。"},
{id:185,ch:2,themeId:"ch2-10",type:"calc",diff:3,q:"売掛金期末残高800,000円、引当率1.5%、引当金期首残高10,000円のとき、当期繰入額はいくらですか？",ans:2000,unit:"円",exp:"必要引当金＝800,000×1.5%＝12,000円。繰入額＝12,000－10,000＝2,000円（差額補充法）。"}
);

window.QUESTIONS.push(
// ===== 第3章：帳簿記入 =====
// ch3-1 仕訳帳の記入方法
{id:186,ch:3,themeId:"ch3-1",type:"choice",diff:1,q:"仕訳帳の役割として正しいものはどれですか？",opts:["取引を発生順に借方・貸方に記録する帳簿","勘定科目ごとに残高を管理する帳簿","商品の入出庫を管理する帳簿","現金の収支を記録する帳簿"],ans:0,exp:"仕訳帳は取引が発生したときに、その取引を借方・貸方に分けて発生順に記録する帳簿です。「序の帳簿」とも呼ばれます。"},
{id:187,ch:3,themeId:"ch3-1",type:"choice",diff:2,q:"仕訳帳の「小書き」とはどれですか？",opts:["取引の内容・摘要を補足する説明文","金額の端数を記入する欄","ページ番号を書く欄","日付を記入する欄"],ans:0,exp:"小書きは仕訳帳の摘要欄に書く取引の簡単な説明文です。「○○商店より商品仕入」など、取引の内容を後から分かるように記録します。"},
{id:188,ch:3,themeId:"ch3-1",type:"choice",diff:2,q:"仕訳帳の元丁欄（丁数欄）に記入するものはどれですか？",opts:["総勘定元帳の該当ページ番号","仕訳帳のページ番号","取引の金額","勘定科目のコード番号"],ans:0,exp:"元丁欄には、その仕訳を転記した総勘定元帳のページ番号（丁数）を記入します。転記が完了したら記入することで、転記漏れを防げます。"},
{id:189,ch:3,themeId:"ch3-1",type:"choice",diff:2,q:"仕訳帳のページ繰越時の記入として正しいものはどれですか？",opts:["ページ末に「次頁へ繰越」と記入し、次ページ冒頭に「前頁より繰越」と記入","新しいページに同じ仕訳を書き直す","繰越の仕訳を新たに起こす","ページ末に合計を記入するだけ"],ans:0,exp:"ページが変わる場合は、旧ページ末に「次頁へ繰越」と借方・貸方合計を記入し、新ページ冒頭に「前頁より繰越」とその合計を記入します。"},
{id:190,ch:3,themeId:"ch3-1",type:"choice",diff:3,q:"複合仕訳（借方または貸方に複数の勘定科目がある仕訳）を仕訳帳に記入するとき、金額欄の書き方として正しいものはどれですか？",opts:["各科目の金額を個別に記入し、合計は最後の行に記入","すべての金額を一箇所に合計して記入","最大金額のみ記入する","科目数が3以上の場合は別ページに記入"],ans:0,exp:"複合仕訳では各勘定科目の金額を行ごとに記入します。最後の行に借方合計・貸方合計を記入することが一般的です。"},
{id:191,ch:3,themeId:"ch3-1",type:"calc",diff:2,q:"仕訳帳の借方合計が1,500,000円のとき、貸方合計はいくらですか？",ans:1500000,unit:"円",exp:"複式簿記の原則により、仕訳帳の借方合計と貸方合計は必ず一致します。借方合計＝貸方合計＝1,500,000円。"},
{id:192,ch:3,themeId:"ch3-1",type:"choice",diff:2,q:"仕訳帳を記入する際の日付の書き方として正しいものはどれですか？",opts:["同一月の取引は月の最初だけ月を記入し、2件目以降は日のみ記入","毎回、年・月・日をすべて記入する","日付は記入不要","月末にまとめて記入する"],ans:0,exp:"仕訳帳では同じ月の取引が続く場合、最初の取引のみ月を記入し、2件目以降は日のみ記入します（月の繰り返し省略）。"},
{id:193,ch:3,themeId:"ch3-1",type:"choice",diff:3,q:"仕訳帳から総勘定元帳への転記の順序として正しいものはどれですか？",opts:["仕訳帳の記入→総勘定元帳への転記→元丁欄への番号記入","元丁欄への番号記入→総勘定元帳への転記→仕訳帳の記入","同時に行う","どの順番でもよい"],ans:0,exp:"まず仕訳帳に記録し、次に各勘定の元帳に転記し、最後に転記した元帳ページ番号を仕訳帳の元丁欄に記入します。"},

// ch3-2 総勘定元帳への転記
{id:194,ch:3,themeId:"ch3-2",type:"choice",diff:1,q:"総勘定元帳の役割として正しいものはどれですか？",opts:["勘定科目ごとに取引を集計・管理する帳簿","取引を発生順に記録する帳簿","現金収支を記録する帳簿","商品の在庫を管理する帳簿"],ans:0,exp:"総勘定元帳は勘定科目ごとにページを設け、各科目の増減を集計・管理する帳簿です。仕訳帳のすべての仕訳がここに転記されます。"},
{id:195,ch:3,themeId:"ch3-2",type:"choice",diff:2,q:"転記の際、元帳の摘要欄（相手科目欄）に記入するものはどれですか？",opts:["仕訳の相手方勘定科目","取引の説明文","仕訳帳のページ番号","金額"],ans:0,exp:"元帳の摘要欄（相手科目欄）には、その仕訳の相手方勘定科目を記入します。例えば（借）現金/（貸）売上の場合、現金の元帳には「売上」と記入します。"},
{id:196,ch:3,themeId:"ch3-2",type:"choice",diff:2,q:"元帳の仕丁欄に記入するものはどれですか？",opts:["仕訳帳のページ番号","元帳のページ番号","取引の日付","勘定科目コード"],ans:0,exp:"仕丁欄には転記の元となった仕訳帳のページ番号を記入します。これにより仕訳帳と元帳の相互参照が可能になります。"},
{id:197,ch:3,themeId:"ch3-2",type:"calc",diff:2,q:"現金勘定：期首残高100,000円、当月借方記入合計500,000円、当月貸方記入合計420,000円。期末残高はいくらですか？",ans:180000,unit:"円",exp:"現金（資産）の残高は借方残高。期末残高＝期首100,000＋借方500,000－貸方420,000＝180,000円。"},
{id:198,ch:3,themeId:"ch3-2",type:"calc",diff:2,q:"買掛金勘定：期首残高200,000円（貸方残高）、当月借方記入300,000円、当月貸方記入400,000円。期末残高はいくらですか？",ans:300000,unit:"円",exp:"買掛金（負債）の残高は貸方残高。期末残高＝期首200,000＋貸方400,000－借方300,000＝300,000円。"},
{id:199,ch:3,themeId:"ch3-2",type:"choice",diff:2,q:"転記の際、元帳の「仕丁」欄に記入する内容として正しいものはどれですか？",opts:["仕訳が記録されている仕訳帳のページ数","元帳のページ数","取引先の名前","転記した日付"],ans:0,exp:"元帳の仕丁欄には、転記元の仕訳帳ページ数を記入します。仕訳帳の元丁欄には元帳のページ数を記入します。"},
{id:200,ch:3,themeId:"ch3-2",type:"choice",diff:2,q:"仕訳帳と総勘定元帳の関係として正しいものはどれですか？",opts:["仕訳帳に記録した取引をすべて総勘定元帳に転記する","総勘定元帳に記録した取引を仕訳帳に転記する","両方は独立していて関係ない","どちらか一方だけあればよい"],ans:0,exp:"仕訳帳が「発生順の日記帳」で、総勘定元帳が「科目別の分類帳」です。仕訳帳のすべての仕訳を元帳の各勘定に転記します。"},
{id:201,ch:3,themeId:"ch3-2",type:"calc",diff:3,q:"売掛金勘定の借方合計700,000円、貸方合計450,000円のとき、残高はいくらですか？",ans:250000,unit:"円",exp:"売掛金（資産）の残高は借方残高。残高＝借方合計700,000－貸方合計450,000＝250,000円。"},

// ch3-3 現金出納帳・当座預金出納帳
{id:202,ch:3,themeId:"ch3-3",type:"choice",diff:1,q:"現金出納帳の役割として正しいものはどれですか？",opts:["現金の収入・支出と残高を日付順に記録する補助帳簿","商品の仕入れと販売を記録する帳簿","得意先ごとの売掛金を管理する帳簿","固定資産の増減を記録する帳簿"],ans:0,exp:"現金出納帳は現金の収入（入金）と支出（出金）を日付順に記録し、現金残高を常に把握できるようにする補助帳簿です。"},
{id:203,ch:3,themeId:"ch3-3",type:"choice",diff:2,q:"現金出納帳で、商品を現金100,000円で販売した場合の記入欄はどれですか？",opts:["収入欄","支出欄","仕入欄","売上欄"],ans:0,exp:"現金が入ってくる（収入）場合は「収入欄」に記入します。現金が出ていく場合は「支出欄」に記入します。"},
{id:204,ch:3,themeId:"ch3-3",type:"calc",diff:2,q:"現金出納帳：前月繰越80,000円、収入合計350,000円、支出合計290,000円。次月繰越（残高）はいくらですか？",ans:140000,unit:"円",exp:"残高＝前月繰越80,000＋収入350,000－支出290,000＝140,000円。"},
{id:205,ch:3,themeId:"ch3-3",type:"choice",diff:1,q:"当座預金出納帳の役割として正しいものはどれですか？",opts:["当座預金の入金・引出しを日付順に記録する補助帳簿","すべての預金を管理する帳簿","小切手の在庫を管理する帳簿","手形の管理帳簿"],ans:0,exp:"当座預金出納帳は当座預金の入金（預入れ）と出金（引出し・小切手振出し）を日付順に記録する補助帳簿です。"},
{id:206,ch:3,themeId:"ch3-3",type:"calc",diff:2,q:"当座預金出納帳：期首残高300,000円、入金合計600,000円、出金合計750,000円。期末残高はいくらですか？",ans:150000,unit:"円",exp:"期末残高＝300,000＋600,000－750,000＝150,000円。"},
{id:207,ch:3,themeId:"ch3-3",type:"choice",diff:3,q:"銀行勘定調整表を作成する主な理由はどれですか？",opts:["帳簿残高と銀行通帳残高の不一致を解明するため","税金の計算のため","小切手の管理のため","従業員の給料を計算するため"],ans:0,exp:"タイムラグ（未取立小切手・未渡小切手・時間外入金など）により帳簿残高と銀行残高が一時的に一致しないことがあります。銀行勘定調整表でその差異を解明します。"},
{id:208,ch:3,themeId:"ch3-3",type:"choice",diff:3,q:"「未取立小切手」の説明として正しいものはどれですか？",opts:["振り出した小切手がまだ銀行に呈示されていないもの","まだ受け取っていない小切手","紛失した小切手","期限切れの小切手"],ans:0,exp:"未取立小切手（未渡小切手ともいう）は、会社が振り出したが相手方がまだ銀行に呈示していない小切手です。帳簿では引落し済みでも、銀行残高にはまだ反映されていません。"},
{id:209,ch:3,themeId:"ch3-3",type:"calc",diff:3,q:"帳簿の当座預金残高200,000円。銀行通帳残高250,000円。差異の原因は未取立小切手50,000円のみ。帳簿の正しい残高はいくらですか？",ans:200000,unit:"円",exp:"未取立小切手がある場合、帳簿には既に引落し記録済みなので帳簿残高に修正は不要。正しい帳簿残高は200,000円のまま。銀行側で50,000円を差し引くと一致します。"},

// ch3-4 売掛金元帳・買掛金元帳
{id:210,ch:3,themeId:"ch3-4",type:"choice",diff:1,q:"売掛金元帳（得意先元帳）の役割として正しいものはどれですか？",opts:["得意先ごとの売掛金残高を管理する補助帳簿","商品ごとの売上を管理する帳簿","販売員ごとの売上を管理する帳簿","月次の売上合計を管理する帳簿"],ans:0,exp:"売掛金元帳（得意先元帳）は得意先（売上先）ごとに売掛金の増減と残高を管理する補助帳簿です。"},
{id:211,ch:3,themeId:"ch3-4",type:"calc",diff:2,q:"A商店の売掛金：期首残高50,000円、当月売上150,000円、当月回収80,000円、返品10,000円。期末残高はいくらですか？",ans:110000,unit:"円",exp:"期末残高＝50,000＋150,000－80,000－10,000＝110,000円。"},
{id:212,ch:3,themeId:"ch3-4",type:"choice",diff:1,q:"買掛金元帳（仕入先元帳）の役割として正しいものはどれですか？",opts:["仕入先ごとの買掛金残高を管理する補助帳簿","商品ごとの仕入原価を管理する帳簿","月次の仕入合計を管理する帳簿","支払い予定日を管理する帳簿"],ans:0,exp:"買掛金元帳（仕入先元帳）は仕入先（購入先）ごとに買掛金の増減と残高を管理する補助帳簿です。"},
{id:213,ch:3,themeId:"ch3-4",type:"calc",diff:2,q:"B商店への買掛金：期首残高80,000円、当月仕入200,000円、当月支払150,000円、返品20,000円。期末残高はいくらですか？",ans:110000,unit:"円",exp:"期末残高＝80,000＋200,000－150,000－20,000＝110,000円。"},
{id:214,ch:3,themeId:"ch3-4",type:"calc",diff:2,q:"A商店売掛金残高100,000円、B商店売掛金残高150,000円、C商店売掛金残高80,000円。売掛金合計はいくらですか？",ans:330000,unit:"円",exp:"売掛金合計＝100,000＋150,000＋80,000＝330,000円。得意先元帳の各残高合計が、総勘定元帳の売掛金残高と一致するはずです。"},
{id:215,ch:3,themeId:"ch3-4",type:"choice",diff:2,q:"統制勘定と補助元帳の関係として正しいものはどれですか？",opts:["総勘定元帳の売掛金残高と売掛金元帳の合計残高は必ず一致する","補助元帳の合計は統制勘定より大きい","両方は独立していて一致しなくてよい","総勘定元帳が補助元帳より詳しい"],ans:0,exp:"総勘定元帳（統制勘定）の売掛金残高と、売掛金元帳（補助元帳）の各得意先残高合計は必ず一致します。これにより記録の正確性を確認できます。"},
{id:216,ch:3,themeId:"ch3-4",type:"choice",diff:2,q:"売掛金を現金で回収したとき、売掛金元帳の記入欄はどれですか？",opts:["回収欄（または貸方欄）","発生欄（または借方欄）","繰越欄","残高欄"],ans:0,exp:"売掛金の回収は売掛金の減少なので、元帳の貸方（回収）欄に記入します。売上発生時は借方（発生）欄に記入します。"},
{id:217,ch:3,themeId:"ch3-4",type:"calc",diff:3,q:"期首売掛金残高（3社合計）200,000円、当月掛け売上合計500,000円、当月回収合計380,000円、当月返品合計20,000円のとき、期末売掛金残高はいくらですか？",ans:300000,unit:"円",exp:"期末残高＝200,000＋500,000－380,000－20,000＝300,000円。"},

// ch3-5 商品有高帳
{id:218,ch:3,themeId:"ch3-5",type:"choice",diff:1,q:"商品有高帳の役割として正しいものはどれですか？",opts:["商品の受入・払出と在庫数量・金額を管理する帳簿","商品の売上金額を管理する帳簿","商品の注文履歴を管理する帳簿","商品の品質を管理する帳簿"],ans:0,exp:"商品有高帳は商品の入庫（受入）・出庫（払出）を記録し、常に在庫数量と金額（原価）を把握するための補助帳簿です。"},
{id:219,ch:3,themeId:"ch3-5",type:"calc",diff:2,q:"先入先出法：前月繰越100個@200円、当月仕入200個@220円、当月払出150個。先入先出法での払出原価はいくらですか？",ans:31000,unit:"円",exp:"先入先出法は古いものから先に払い出します。100個×200円＝20,000円＋50個×220円＝11,000円。合計31,000円。"},
{id:220,ch:3,themeId:"ch3-5",type:"calc",diff:2,q:"移動平均法：前月繰越100個@200円（合計20,000円）、当月仕入100個@220円（合計22,000円）。払出時の移動平均単価はいくらですか？",ans:210,unit:"円",exp:"移動平均単価＝（20,000＋22,000）÷（100＋100）＝42,000÷200＝210円。仕入のたびに新しい平均単価を計算します。"},
{id:221,ch:3,themeId:"ch3-5",type:"calc",diff:2,q:"先入先出法：期首100個@100円、仕入100個@120円、払出150個。期末在庫金額はいくらですか？",ans:6000,unit:"円",exp:"先入先出法では古いものから払い出します。払出：100個@100円＋50個@120円。残りは50個@120円＝6,000円。"},
{id:222,ch:3,themeId:"ch3-5",type:"calc",diff:2,q:"移動平均法：期首100個@100円（10,000円）、仕入100個@120円（12,000円）、払出150個。払出原価はいくらですか？（移動平均単価：110円）",ans:16500,unit:"円",exp:"移動平均単価＝（10,000＋12,000）÷200＝110円。払出原価＝150個×110円＝16,500円。"},
{id:223,ch:3,themeId:"ch3-5",type:"calc",diff:2,q:"先入先出法での期末在庫：50個@120円。売上原価を求めなさい。期首在庫10,000円、当期仕入12,000円、期末在庫6,000円。",ans:16000,unit:"円",exp:"売上原価＝期首在庫10,000＋仕入12,000－期末在庫6,000＝16,000円。"},
{id:224,ch:3,themeId:"ch3-5",type:"choice",diff:2,q:"先入先出法と移動平均法の説明として正しいものはどれですか？",opts:["先入先出法は古い在庫から払い出し、移動平均法は仕入のたびに平均単価を再計算する","先入先出法は常に平均単価を使い、移動平均法は古い順に払い出す","両方とも全く同じ結果になる","先入先出法の方が常に在庫金額が低くなる"],ans:0,exp:"先入先出法（FIFO）は先に仕入れた商品から先に払い出すと仮定します。移動平均法は仕入れのたびに新しい平均単価を計算して使います。"},
{id:225,ch:3,themeId:"ch3-5",type:"calc",diff:3,q:"期首在庫50個@200円、4/5仕入100個@210円、4/15払出80個（移動平均法）。4/15の払出原価はいくらですか？",ans:16640,unit:"円",exp:"4/5仕入後の平均単価＝（50×200＋100×210）÷150＝（10,000＋21,000）÷150＝31,000÷150≒206.67円。払出80個×206.67≒16,533円。（注：端数処理により16,533〜16,560円程度）"},

// ===== 第4章：試算表 =====
// ch4-1 合計試算表
{id:226,ch:4,themeId:"ch4-1",type:"choice",diff:1,q:"合計試算表とはどのようなものですか？",opts:["各勘定科目の借方合計と貸方合計を記載した試算表","各勘定科目の残高のみを記載した試算表","借方合計と残高の両方を記載した試算表","仕訳帳の合計を集計した表"],ans:0,exp:"合計試算表は各勘定科目について仕訳帳から転記した借方の合計金額と貸方の合計金額を一覧にした試算表です。"},
{id:227,ch:4,themeId:"ch4-1",type:"choice",diff:1,q:"試算表を作成する主な目的はどれですか？",opts:["転記や計算ミスを発見するため","確定申告のため","利益を計算するため","商品の在庫を確認するため"],ans:0,exp:"試算表の主な目的は、仕訳帳から元帳への転記が正確に行われているかを確認することです。借方合計＝貸方合計にならない場合は誤りがあります。"},
{id:228,ch:4,themeId:"ch4-1",type:"calc",diff:2,q:"現金勘定：借方記入は①100,000②50,000③80,000④200,000。借方合計はいくらですか？",ans:430000,unit:"円",exp:"借方合計＝100,000＋50,000＋80,000＋200,000＝430,000円。"},
{id:229,ch:4,themeId:"ch4-1",type:"calc",diff:2,q:"売掛金勘定の貸方記入：①30,000②50,000③20,000④80,000。貸方合計はいくらですか？",ans:180000,unit:"円",exp:"貸方合計＝30,000＋50,000＋20,000＋80,000＝180,000円。"},
{id:230,ch:4,themeId:"ch4-1",type:"choice",diff:1,q:"合計試算表において、借方合計と貸方合計の関係はどうなりますか？",opts:["必ず等しくなる","借方が大きい","貸方が大きい","科目によって異なる"],ans:0,exp:"複式簿記の原則により、すべての仕訳の借方合計と貸方合計は必ず等しくなるため、合計試算表の借方合計＝貸方合計になります。"},
{id:231,ch:4,themeId:"ch4-1",type:"calc",diff:2,q:"合計試算表で、貸方合計が2,000,000円のとき、借方合計はいくらですか？",ans:2000000,unit:"円",exp:"合計試算表の借方合計＝貸方合計。借方合計＝2,000,000円。"},
{id:232,ch:4,themeId:"ch4-1",type:"calc",diff:3,q:"仕訳データ：①（借）現金100,000/（貸）売上100,000　②（借）仕入80,000/（貸）現金80,000　③（借）売掛金50,000/（貸）売上50,000。現金勘定の借方合計はいくらですか？",ans:100000,unit:"円",exp:"現金の借方記入は①の100,000円のみ。②は現金の貸方記入なので借方合計には含まれません。"},
{id:233,ch:4,themeId:"ch4-1",type:"choice",diff:2,q:"合計試算表に記入する金額はどれですか？",opts:["仕訳帳に記録された各勘定の借方・貸方への記入合計","期末残高","元帳の残高","決算整理後の金額"],ans:0,exp:"合計試算表には仕訳帳から元帳に転記されたすべての金額の合計を記入します。期末残高（残高試算表）とは異なります。"},
{id:234,ch:4,themeId:"ch4-1",type:"choice",diff:2,q:"合計試算表に含まれない項目はどれですか？",opts:["1件も取引のなかった勘定科目","借方が大きい勘定科目","貸方が大きい勘定科目","資産の勘定科目"],ans:0,exp:"合計試算表には取引が発生した勘定科目のみ記載されます。一度も使われていない勘定科目は記載されません。"},
{id:235,ch:4,themeId:"ch4-1",type:"calc",diff:3,q:"売上勘定の貸方記入：①200,000②150,000③300,000④100,000。合計試算表の売上欄・貸方合計はいくらですか？",ans:750000,unit:"円",exp:"売上勘定の貸方合計＝200,000＋150,000＋300,000＋100,000＝750,000円。"},
{id:236,ch:4,themeId:"ch4-1",type:"calc",diff:3,q:"合計試算表：借方合計3,500,000円、各科目の貸方合計3,200,000円+不明科目。不明科目の貸方合計はいくらですか？",ans:300000,unit:"円",exp:"借方合計＝貸方合計なので、不明科目の貸方＝3,500,000－3,200,000＝300,000円。"},
{id:237,ch:4,themeId:"ch4-1",type:"calc",diff:3,q:"現金勘定：借方合計800,000円、貸方合計650,000円。残高試算表の現金残高はいくらですか？",ans:150000,unit:"円",exp:"現金（資産）の残高＝借方合計－貸方合計＝800,000－650,000＝150,000円。"},

// ch4-2 残高試算表
{id:238,ch:4,themeId:"ch4-2",type:"choice",diff:1,q:"残高試算表とはどのようなものですか？",opts:["各勘定科目の期末残高を記載した試算表","各勘定科目の借方・貸方合計を記載した試算表","決算後の財務諸表","仕訳帳の一覧表"],ans:0,exp:"残高試算表は各勘定科目の残高（借方合計と貸方合計の差額）を一覧にした試算表です。資産・費用は借方残高、負債・純資産・収益は貸方残高になります。"},
{id:239,ch:4,themeId:"ch4-2",type:"calc",diff:2,q:"現金勘定：借方合計600,000円、貸方合計480,000円。残高はいくらですか？（残高試算表用）",ans:120000,unit:"円",exp:"現金（資産）残高＝借方合計600,000－貸方合計480,000＝120,000円（借方残高）。"},
{id:240,ch:4,themeId:"ch4-2",type:"choice",diff:2,q:"資産の勘定科目の残高の場所はどこですか？",opts:["借方（左側）","貸方（右側）","どちらでもよい","科目によって異なる"],ans:0,exp:"資産勘定は通常、増加（借方）が減少（貸方）を上回るため、借方残高（左側）になります。現金・売掛金・備品なども借方残高です。"},
{id:241,ch:4,themeId:"ch4-2",type:"choice",diff:2,q:"負債の勘定科目の残高の場所はどこですか？",opts:["貸方（右側）","借方（左側）","どちらでもよい","ゼロになる"],ans:0,exp:"負債勘定は通常、増加（貸方）が減少（借方）を上回るため、貸方残高（右側）になります。買掛金・借入金・支払手形なども貸方残高です。"},
{id:242,ch:4,themeId:"ch4-2",type:"calc",diff:2,q:"売上勘定：借方合計50,000円（返品・値引き分）、貸方合計800,000円。残高はいくらですか？",ans:750000,unit:"円",exp:"売上（収益）残高＝貸方合計800,000－借方合計50,000＝750,000円（貸方残高）。"},
{id:243,ch:4,themeId:"ch4-2",type:"calc",diff:2,q:"給料勘定の借方合計が360,000円のとき、残高試算表の給料欄はいくらですか？（貸方記入なし）",ans:360000,unit:"円",exp:"費用勘定（給料）は借方に記入されます。貸方記入がなければ残高＝借方合計＝360,000円（借方残高）。"},
{id:244,ch:4,themeId:"ch4-2",type:"choice",diff:2,q:"次のうち、残高試算表で借方残高になる勘定科目はどれですか？",opts:["建物","売上","買掛金","資本金"],ans:0,exp:"建物は資産なので借方残高。売上は収益（貸方残高）、買掛金は負債（貸方残高）、資本金は純資産（貸方残高）です。"},
{id:245,ch:4,themeId:"ch4-2",type:"choice",diff:2,q:"次のうち、残高試算表で貸方残高になる勘定科目はどれですか？",opts:["借入金","仕入","売掛金","備品"],ans:0,exp:"借入金は負債なので貸方残高。仕入は費用（借方残高）、売掛金は資産（借方残高）、備品は資産（借方残高）です。"},
{id:246,ch:4,themeId:"ch4-2",type:"calc",diff:2,q:"残高試算表：借方残高合計1,800,000円。貸方残高合計はいくらですか？",ans:1800000,unit:"円",exp:"残高試算表でも借方残高合計＝貸方残高合計になります。複式簿記の原則は残高試算表でも成立します。"},
{id:247,ch:4,themeId:"ch4-2",type:"calc",diff:3,q:"残高試算表で、資産合計1,200,000円、負債合計500,000円のとき、純資産（資本金+利益）はいくらですか？",ans:700000,unit:"円",exp:"貸借対照表等式：資産＝負債＋純資産。純資産＝資産－負債＝1,200,000－500,000＝700,000円。"},
{id:248,ch:4,themeId:"ch4-2",type:"choice",diff:2,q:"残高試算表から損益計算書に記載するものはどれですか？",opts:["収益・費用の勘定科目","資産・負債・純資産の勘定科目","すべての勘定科目","資産の勘定科目のみ"],ans:0,exp:"損益計算書には収益と費用の勘定科目を記載します。資産・負債・純資産は貸借対照表に記載します。"},
{id:249,ch:4,themeId:"ch4-2",type:"calc",diff:3,q:"残高試算表：現金150,000、売掛金300,000、仕入400,000、売上700,000、買掛金200,000。資産合計はいくらですか？",ans:450000,unit:"円",exp:"資産＝現金150,000＋売掛金300,000＝450,000円。仕入は費用、売上は収益、買掛金は負債なので資産合計には含めません。"},

// ch4-3 合計残高試算表
{id:250,ch:4,themeId:"ch4-3",type:"choice",diff:1,q:"合計残高試算表の説明として正しいものはどれですか？",opts:["合計試算表と残高試算表を合わせた形式の試算表","合計試算表と残高試算表のどちらか一方","残高のみを記載した試算表","合計のみを記載した試算表"],ans:0,exp:"合計残高試算表は、合計試算表（借方・貸方合計）と残高試算表（借方・貸方残高）を一つの表にまとめたものです。"},
{id:251,ch:4,themeId:"ch4-3",type:"choice",diff:2,q:"合計残高試算表の列（欄）は何列ありますか？",opts:["6列（借方合計・借方残高・科目・貸方残高・貸方合計）","4列（借方・貸方・科目・残高）","2列（借方・貸方）","8列"],ans:0,exp:"合計残高試算表は通常6欄（借方残高・借方合計・科目・貸方合計・貸方残高）の構成です。"},
{id:252,ch:4,themeId:"ch4-3",type:"calc",diff:2,q:"現金：借方合計500,000円、貸方合計350,000円。合計残高試算表の現金行・借方残高はいくらですか？",ans:150000,unit:"円",exp:"資産の残高は借方残高＝借方合計－貸方合計＝500,000－350,000＝150,000円。"},
{id:253,ch:4,themeId:"ch4-3",type:"calc",diff:2,q:"買掛金：借方合計200,000円、貸方合計400,000円。合計残高試算表の買掛金行・貸方残高はいくらですか？",ans:200000,unit:"円",exp:"負債の残高は貸方残高＝貸方合計－借方合計＝400,000－200,000＝200,000円。"},
{id:254,ch:4,themeId:"ch4-3",type:"calc",diff:3,q:"合計残高試算表で、借方合計合計＝3,000,000円のとき、貸方合計合計はいくらですか？",ans:3000000,unit:"円",exp:"合計欄は合計試算表と同じく借方合計合計＝貸方合計合計。"},
{id:255,ch:4,themeId:"ch4-3",type:"calc",diff:3,q:"合計残高試算表で、借方残高合計＝1,500,000円のとき、貸方残高合計はいくらですか？",ans:1500000,unit:"円",exp:"残高欄は残高試算表と同じく借方残高合計＝貸方残高合計。"},
{id:256,ch:4,themeId:"ch4-3",type:"calc",diff:3,q:"ある勘定科目：借方合計700,000円、貸方残高300,000円。この科目の貸方合計はいくらですか？",ans:1000000,unit:"円",exp:"貸方残高＝貸方合計－借方合計。300,000＝貸方合計－700,000。貸方合計＝1,000,000円。"},
{id:257,ch:4,themeId:"ch4-3",type:"calc",diff:3,q:"ある資産勘定：借方合計400,000円、借方残高150,000円。貸方合計はいくらですか？",ans:250000,unit:"円",exp:"資産の借方残高＝借方合計－貸方合計。150,000＝400,000－貸方合計。貸方合計＝250,000円。"},
{id:258,ch:4,themeId:"ch4-3",type:"calc",diff:2,q:"仕入勘定：借方合計600,000円、貸方合計50,000円（返品分）。借方残高はいくらですか？",ans:550000,unit:"円",exp:"費用（仕入）の残高は借方残高＝借方合計－貸方合計＝600,000－50,000＝550,000円。"},
{id:259,ch:4,themeId:"ch4-3",type:"calc",diff:3,q:"売上：借方合計30,000円（返品）、貸方合計800,000円。売上の貸方残高はいくらですか？",ans:770000,unit:"円",exp:"収益（売上）の残高は貸方残高＝貸方合計800,000－借方合計30,000＝770,000円。"},
{id:260,ch:4,themeId:"ch4-3",type:"calc",diff:3,q:"合計残高試算表で、資本金の貸方合計＝1,000,000円、借方合計＝0円のとき、貸方残高はいくらですか？",ans:1000000,unit:"円",exp:"資本金（純資産）の貸方残高＝貸方合計1,000,000－借方合計0＝1,000,000円。"},
{id:261,ch:4,themeId:"ch4-3",type:"choice",diff:2,q:"合計残高試算表について正しいものはどれですか？",opts:["借方合計合計＝貸方合計合計、かつ借方残高合計＝貸方残高合計","借方合計合計のみ一致すればよい","残高の合計だけ一致すればよい","どちらも一致しなくてよい"],ans:0,exp:"合計残高試算表では、合計欄（借方合計合計＝貸方合計合計）と残高欄（借方残高合計＝貸方残高合計）の両方が一致します。"},

// ch4-4 試算表の誤りの発見
{id:262,ch:4,themeId:"ch4-4",type:"choice",diff:2,q:"試算表の借方合計≠貸方合計になったとき、確実に存在する誤りはどれですか？",opts:["転記ミス（一方だけ転記した、または金額が違う）","同じ科目に重複して記入した","正しい仕訳を誤った科目で記入した","借方と貸方を入れ替えて記入した"],ans:0,exp:"試算表が不一致になるのは、一方だけ転記漏れや片方の金額が違う場合です。正しい金額で逆方向に記入した場合は金額が同じなので一致します。"},
{id:263,ch:4,themeId:"ch4-4",type:"choice",diff:2,q:"試算表が一致していても検出できない誤りはどれですか？",opts:["借方と貸方の科目を入れ替えた誤り","片方だけ記入した誤り","金額を1ケタ間違えた誤り","転記を2回した誤り"],ans:0,exp:"借方・貸方の金額が同額で科目だけ間違えた場合、試算表は一致するため誤りを検出できません。これを「不可検出誤謬」といいます。"},
{id:264,ch:4,themeId:"ch4-4",type:"choice",diff:3,q:"仕訳の借方に50,000円と記入すべきところを500,000円と記入してしまった。試算表はどうなりますか？",opts:["借方合計が450,000円大きくなる（不一致）","貸方合計が450,000円大きくなる（不一致）","試算表は一致する","借方と貸方両方が450,000円大きくなる"],ans:0,exp:"借方のみ500,000円と記入し、貸方は正しく50,000円のままなら、借方が450,000円多くなり不一致になります。"},
{id:265,ch:4,themeId:"ch4-4",type:"choice",diff:3,q:"借方100,000円・貸方100,000円の正しい仕訳を、借方90,000円・貸方90,000円と記入してしまった。試算表はどうなりますか？",opts:["試算表は一致するが金額が誤っている","借方が不足して不一致になる","貸方が不足して不一致になる","試算表は正しい"],ans:0,exp:"借方と貸方の金額が同額で間違っているため、試算表は一致します。しかし金額が10,000円ずつ少ないという誤りは試算表では発見できません。"},
{id:266,ch:4,themeId:"ch4-4",type:"choice",diff:3,q:"現金の増加を借方に記入すべきところ、誤って当座預金の借方に記入してしまった。試算表はどうなりますか？",opts:["試算表は一致するが科目が誤っている","借方が不足して不一致になる","貸方が不足して不一致になる","試算表全体が正しい"],ans:0,exp:"科目の間違いでも金額は同じ（借方に同額記入）なので試算表は一致します。試算表では科目の誤りは検出できません。"},
{id:267,ch:4,themeId:"ch4-4",type:"calc",diff:3,q:"残高試算表で借方合計2,100,000円、貸方合計2,050,000円。差額はどれだけの誤りがあることを示しますか？",ans:50000,unit:"円",exp:"差額＝2,100,000－2,050,000＝50,000円。この差額分の転記漏れや金額誤りがあります。"},
{id:268,ch:4,themeId:"ch4-4",type:"journal",diff:3,q:"現金100,000円を貸付金として正しく仕訳したが、元帳転記時に現金の貸方に10,000円しか転記しなかった。訂正のための仕訳は？",entries:[{dr:"現金",cr:"現金",amt:90000}],exp:"実際は100,000円転記すべきところ10,000円しか転記しなかったので不足分90,000円を追記。（注：実務では元帳に直接訂正か、訂正仕訳を起こします）"},
{id:269,ch:4,themeId:"ch4-4",type:"choice",diff:2,q:"仕訳を2回重複して転記してしまった場合、試算表はどうなりますか？",opts:["借方・貸方ともに同額増えるため一致する（ただし金額が過大）","借方だけが増えて不一致になる","貸方だけが増えて不一致になる","変化なし"],ans:0,exp:"同じ仕訳を2回転記すると借方・貸方の両方が同額増えるため試算表は一致します。ただし各科目の金額が過大になるという誤りは発見できません。"},
{id:270,ch:4,themeId:"ch4-4",type:"choice",diff:2,q:"誤りを訂正する方法として最も一般的なものはどれですか？",opts:["正しい仕訳と誤った仕訳の差額を訂正仕訳として記録する","誤った仕訳を削除して書き直す","誤った金額に線を引いて上書きする","帳簿を新しく書き直す"],ans:0,exp:"帳簿の誤りは削除・修正せず、誤った仕訳を取り消す逆仕訳を行い、正しい仕訳を新たに記録するか、差額の訂正仕訳を起こすことが正しい方法です。"}
);

window.QUESTIONS.push(
// ===== 第5章：決算・財務諸表 =====
// ch5-1 決算整理仕訳の全パターン
{id:271,ch:5,themeId:"ch5-1",type:"journal",diff:2,q:"決算整理：期首の繰越商品残高40,000円を仕入勘定に振り替えた。（仕入に振替）",entries:[{dr:"仕入",cr:"繰越商品",amt:40000}],exp:"期首商品の振替仕訳：仕入（費用）増加→借方、繰越商品（資産）減少→貸方。これにより期首在庫が売上原価の計算に組み込まれます。"},
{id:272,ch:5,themeId:"ch5-1",type:"journal",diff:2,q:"決算整理：期末棚卸しにより商品残高が55,000円と判明した。（繰越商品に振替）",entries:[{dr:"繰越商品",cr:"仕入",amt:55000}],exp:"期末商品の振替仕訳：繰越商品（資産）増加→借方、仕入（費用）減少→貸方。期末在庫を資産として繰り越します。"},
{id:273,ch:5,themeId:"ch5-1",type:"journal",diff:2,q:"決算整理：備品（取得原価300,000円・残存価額0円・耐用年数5年）の減価償却を間接法で行った。",entries:[{dr:"減価償却費",cr:"減価償却累計額",amt:60000}],exp:"300,000÷5＝60,000円。減価償却費（費用）60,000円（借方）、減価償却累計額60,000円増加（貸方）。間接法なので資産を直接減らしません。"},
{id:274,ch:5,themeId:"ch5-1",type:"journal",diff:2,q:"決算整理：支払保険料の前払い分24,000円を前払費用に振り替えた。",entries:[{dr:"前払費用",cr:"支払保険料",amt:24000}],exp:"前払費用（資産）増加→借方、支払保険料（費用）減少→貸方。翌期に属する費用を資産（前払費用）に振り替えます。"},
{id:275,ch:5,themeId:"ch5-1",type:"journal",diff:2,q:"決算整理：未払給料30,000円を計上した。",entries:[{dr:"給料",cr:"未払費用",amt:30000}],exp:"給料（費用）増加→借方、未払費用（負債）増加→貸方。当期に発生したが未払いの費用を計上します。"},
{id:276,ch:5,themeId:"ch5-1",type:"journal",diff:2,q:"決算整理：前受家賃のうち翌期分18,000円を前受収益に振り替えた。",entries:[{dr:"受取家賃",cr:"前受収益",amt:18000}],exp:"受取家賃（収益）減少→借方、前受収益（負債）増加→貸方。翌期分の収益を負債（前受収益）に振り替えます。"},
{id:277,ch:5,themeId:"ch5-1",type:"journal",diff:2,q:"決算整理：貸付金の未収利息6,000円を計上した。",entries:[{dr:"未収収益",cr:"受取利息",amt:6000}],exp:"未収収益（資産）増加→借方、受取利息（収益）発生→貸方。当期に発生したが未収の収益を計上します。"},
{id:278,ch:5,themeId:"ch5-1",type:"journal",diff:2,q:"決算整理：売掛金残高400,000円に対して2%の貸倒引当金を設定。既存残高3,000円あり。",entries:[{dr:"貸倒引当金繰入",cr:"貸倒引当金",amt:5000}],exp:"必要額＝400,000×2%＝8,000円。追加繰入額＝8,000－3,000＝5,000円（差額補充法）。"},
{id:279,ch:5,themeId:"ch5-1",type:"choice",diff:1,q:"決算整理仕訳とはどのようなものですか？",opts:["期末に財務諸表を正確に作るために行う修正仕訳","日常の取引を記録する仕訳","期首に行う仕訳","税金を計算するための仕訳"],ans:0,exp:"決算整理仕訳とは、期末（決算時）に財務諸表を正確に作成するために行う修正仕訳です。減価償却・前払費用・貸倒引当金など複数のパターンがあります。"},
{id:280,ch:5,themeId:"ch5-1",type:"choice",diff:2,q:"次のうち決算整理仕訳に含まれるものはどれですか？",opts:["減価償却費の計上","商品の現金仕入れ","買掛金の現金払い","売掛金の回収"],ans:0,exp:"決算整理仕訳には①商品棚卸②減価償却③貸倒引当金設定④前払・前受・未払・未収の調整が含まれます。日常取引（仕入・売上・回収・支払い）は含まれません。"},
{id:281,ch:5,themeId:"ch5-1",type:"calc",diff:2,q:"10月1日に支払った保険料1年分240,000円のうち、3月31日決算での前払保険料はいくらですか？",ans:120000,unit:"円",exp:"翌期分（4〜9月）の6か月分＝240,000×6/12＝120,000円が前払費用になります。"},
{id:282,ch:5,themeId:"ch5-1",type:"calc",diff:2,q:"8月1日から1年間の家賃として受け取った120,000円のうち、3月31日決算での前受収益はいくらですか？",ans:40000,unit:"円",exp:"翌期分（4〜7月）の4か月分＝120,000×4/12＝40,000円が前受収益（負債）になります。"},
{id:283,ch:5,themeId:"ch5-1",type:"calc",diff:2,q:"借入金500,000円、年利率3%、借入日10月1日、決算3月31日。未払利息はいくらですか？",ans:7500,unit:"円",exp:"未払利息＝500,000×3%×6/12＝7,500円。10月〜3月の6か月分を未払費用として計上します。"},
{id:284,ch:5,themeId:"ch5-1",type:"calc",diff:2,q:"期末売掛金600,000円、引当率1%、前期末引当金残高4,000円。当期繰入額はいくらですか？",ans:2000,unit:"円",exp:"必要額＝600,000×1%＝6,000円。追加繰入＝6,000－4,000＝2,000円。"},
{id:285,ch:5,themeId:"ch5-1",type:"journal",diff:3,q:"期首商品60,000円、期末商品（棚卸額）45,000円。決算整理の2つの仕訳をまとめて行いなさい。①期首商品の仕入への振替、②期末商品の繰越商品への振替",entries:[{dr:"仕入",cr:"繰越商品",amt:60000},{dr:"繰越商品",cr:"仕入",amt:45000}],exp:"①（借）仕入60,000/（貸）繰越商品60,000　②（借）繰越商品45,000/（貸）仕入45,000。これにより売上原価に期首在庫が加算され、期末在庫が控除されます。"},

// ch5-2 精算表の作成
{id:286,ch:5,themeId:"ch5-2",type:"choice",diff:1,q:"精算表の役割として正しいものはどれですか？",opts:["残高試算表から決算整理を経て財務諸表を作成するまでの過程を一表にまとめたもの","決算整理仕訳だけを記録したもの","試算表の別名","財務諸表の別名"],ans:0,exp:"精算表は残高試算表・修正記入（決算整理）・損益計算書・貸借対照表の各欄を一つの表にまとめたワークシートです。"},
{id:287,ch:5,themeId:"ch5-2",type:"choice",diff:2,q:"精算表の列（欄）数はいくつですか？（一般的な形式）",opts:["8欄（残高試算表借方・貸方、修正記入借方・貸方、P/L借方・貸方、B/S借方・貸方）","6欄","4欄","10欄"],ans:0,exp:"標準的な精算表は8欄形式：①残高試算表（借方・貸方）②修正記入（借方・貸方）③損益計算書（借方・貸方）④貸借対照表（借方・貸方）。"},
{id:288,ch:5,themeId:"ch5-2",type:"choice",diff:2,q:"精算表の「修正記入」欄に記入するものはどれですか？",opts:["決算整理仕訳の金額","期中の仕訳の金額","残高試算表の残高","財務諸表の数値"],ans:0,exp:"修正記入欄には決算整理仕訳（前払費用の調整、減価償却など）の金額を記入します。残高試算表の残高に修正記入を加算・減算して、損益計算書欄・貸借対照表欄に記入します。"},
{id:289,ch:5,themeId:"ch5-2",type:"calc",diff:2,q:"精算表：給料の残高試算表借方残高300,000円、修正記入借方（未払給料）30,000円。損益計算書欄の給料（費用）はいくらですか？",ans:330000,unit:"円",exp:"費用の場合：残高（借方）300,000＋修正（借方）30,000＝330,000円。未払給料分が費用に加算されます。"},
{id:290,ch:5,themeId:"ch5-2",type:"calc",diff:2,q:"精算表：支払保険料の残高試算表借方120,000円、修正記入（前払い振替）貸方24,000円。損益計算書欄はいくらですか？",ans:96000,unit:"円",exp:"支払保険料（費用）＝120,000－24,000＝96,000円。前払い分は費用から控除されます。"},
{id:291,ch:5,themeId:"ch5-2",type:"calc",diff:2,q:"精算表：前払費用の残高試算表残高0円、修正記入借方24,000円。貸借対照表欄の前払費用（資産）はいくらですか？",ans:24000,unit:"円",exp:"前払費用（資産）は貸借対照表欄に記入。残高0＋修正24,000＝24,000円（借方・資産）。"},
{id:292,ch:5,themeId:"ch5-2",type:"calc",diff:3,q:"精算表：P/L欄の収益合計1,000,000円、費用合計800,000円。当期純利益はいくらですか？",ans:200000,unit:"円",exp:"当期純利益＝収益合計1,000,000－費用合計800,000＝200,000円。P/L欄の収益合計＞費用合計の差額が当期純利益です。"},
{id:293,ch:5,themeId:"ch5-2",type:"calc",diff:3,q:"精算表P/L欄：収益（貸方）合計800,000円、費用（借方）合計650,000円。当期純利益はいくらで、どちらの欄に記入しますか？",ans:150000,unit:"円",exp:"当期純利益＝800,000－650,000＝150,000円。P/L欄の借方（費用側）に記入し、B/S欄の貸方（資本側）にも記入します。"},
{id:294,ch:5,themeId:"ch5-2",type:"choice",diff:3,q:"精算表のB/S欄（貸借対照表欄）に記入する項目はどれですか？",opts:["資産・負債・純資産の勘定科目","収益・費用の勘定科目","すべての勘定科目","期中取引のみ"],ans:0,exp:"B/S欄には資産・負債・純資産の勘定科目を記入します。収益・費用はP/L欄に記入します。繰越商品・前払費用・未払費用なども資産・負債なのでB/S欄です。"},
{id:295,ch:5,themeId:"ch5-2",type:"choice",diff:2,q:"精算表において、当期純損失が発生した場合の記入について正しいものはどれですか？",opts:["P/L欄の貸方（収益側）に記入し、B/S欄の借方（資産側）に記入する","P/L欄の借方に記入し、B/S欄の貸方に記入する","P/L欄の借方と貸方の両方に記入する","記入しない"],ans:0,exp:"当期純損失（費用＞収益）の場合、P/L欄の貸方（収益側）に記入してバランスをとり、B/S欄の借方（資産側のマイナス・純資産の減少）に記入します。"},

// ch5-3 損益計算書の作成
{id:296,ch:5,themeId:"ch5-3",type:"choice",diff:1,q:"損益計算書（P/L）の説明として正しいものはどれですか？",opts:["一定期間の収益・費用・利益を表す財務諸表","一時点の資産・負債・純資産を表す財務諸表","現金の収支を表す財務諸表","商品の売上だけを表す財務諸表"],ans:0,exp:"損益計算書（P/L：Profit and Loss Statement）は一定期間（通常1年）の収益・費用・利益を示す財務諸表です。「いくら稼いで、いくら使って、いくら儲かったか」を表します。"},
{id:297,ch:5,themeId:"ch5-3",type:"calc",diff:2,q:"売上高900,000円、売上原価620,000円のとき、売上総利益はいくらですか？",ans:280000,unit:"円",exp:"売上総利益＝売上高900,000－売上原価620,000＝280,000円。売上総利益は「粗利」ともいい、商品販売の基本的な利益です。"},
{id:298,ch:5,themeId:"ch5-3",type:"calc",diff:2,q:"売上総利益280,000円、販売費及び一般管理費（給料・家賃等）150,000円のとき、営業利益はいくらですか？",ans:130000,unit:"円",exp:"営業利益＝売上総利益280,000－販売費及び一般管理費150,000＝130,000円。本業の利益を表します。"},
{id:299,ch:5,themeId:"ch5-3",type:"calc",diff:2,q:"営業利益130,000円、受取利息5,000円、支払利息8,000円のとき、経常利益はいくらですか？",ans:127000,unit:"円",exp:"経常利益＝営業利益130,000＋受取利息5,000－支払利息8,000＝127,000円。"},
{id:300,ch:5,themeId:"ch5-3",type:"calc",diff:2,q:"収益合計1,200,000円、費用合計950,000円のとき、当期純利益はいくらですか？",ans:250000,unit:"円",exp:"当期純利益＝収益合計1,200,000－費用合計950,000＝250,000円。"},
{id:301,ch:5,themeId:"ch5-3",type:"choice",diff:2,q:"損益計算書に記載しない勘定科目はどれですか？",opts:["売掛金","売上","仕入","受取利息"],ans:0,exp:"売掛金は資産なので貸借対照表に記載します。損益計算書には収益（売上・受取利息等）と費用（仕入・給料等）のみ記載します。"},
{id:302,ch:5,themeId:"ch5-3",type:"calc",diff:2,q:"売上高600,000円、売上原価420,000円のとき、売上総利益率は何%ですか？（小数点以下切り捨て）",ans:30,unit:"%",exp:"売上総利益率＝売上総利益÷売上高×100＝180,000÷600,000×100＝30%。"},
{id:303,ch:5,themeId:"ch5-3",type:"choice",diff:2,q:"損益計算書の費用に含まれるものはどれですか？",opts:["減価償却費","現金","受取家賃","繰越商品"],ans:0,exp:"減価償却費は費用なので損益計算書の費用に記載します。現金・繰越商品は資産（B/S）、受取家賃は収益（P/L収益側）です。"},
{id:304,ch:5,themeId:"ch5-3",type:"choice",diff:2,q:"損益計算書の構造として正しいものはどれですか？",opts:["収益－費用＝当期純利益（または純損失）","資産－負債＝純資産","収入－支出＝残高","売上－仕入＝利益"],ans:0,exp:"損益計算書は「収益－費用＝当期純利益（収益＞費用）または当期純損失（収益＜費用）」を示す財務諸表です。"},
{id:305,ch:5,themeId:"ch5-3",type:"calc",diff:3,q:"損益計算書：売上高800,000円、売上原価530,000円、販売費120,000円、受取利息10,000円、支払利息5,000円。当期純利益はいくらですか？",ans:155000,unit:"円",exp:"売上総利益＝270,000。営業利益＝270,000－120,000＝150,000。純利益＝150,000＋10,000－5,000＝155,000円。"},

// ch5-4 貸借対照表の作成
{id:306,ch:5,themeId:"ch5-4",type:"choice",diff:1,q:"貸借対照表（B/S）の説明として正しいものはどれですか？",opts:["一定時点の資産・負債・純資産の状況を表す財務諸表","一定期間の収益・費用・利益を表す財務諸表","現金の収支状況を表す財務諸表","商品の在庫状況を表す財務諸表"],ans:0,exp:"貸借対照表（B/S：Balance Sheet）は決算日（一定時点）における企業の財政状態（資産・負債・純資産の状況）を示す財務諸表です。"},
{id:307,ch:5,themeId:"ch5-4",type:"calc",diff:2,q:"現金150,000円、売掛金300,000円、商品80,000円、備品400,000円（減価償却累計額80,000円）。資産合計はいくらですか？",ans:850000,unit:"円",exp:"資産合計＝150,000＋300,000＋80,000＋（400,000－80,000）＝850,000円。備品は帳簿価額（取得原価－累計額）で表示します。"},
{id:308,ch:5,themeId:"ch5-4",type:"calc",diff:2,q:"買掛金200,000円、借入金300,000円、未払費用30,000円。負債合計はいくらですか？",ans:530000,unit:"円",exp:"負債合計＝200,000＋300,000＋30,000＝530,000円。"},
{id:309,ch:5,themeId:"ch5-4",type:"calc",diff:2,q:"資産合計1,500,000円、負債合計800,000円のとき、純資産合計はいくらですか？",ans:700000,unit:"円",exp:"純資産＝資産1,500,000－負債800,000＝700,000円。貸借対照表等式：資産＝負債＋純資産。"},
{id:310,ch:5,themeId:"ch5-4",type:"calc",diff:2,q:"資産合計2,000,000円。負債合計1,200,000円、資本金500,000円。当期純利益はいくらですか？",ans:300000,unit:"円",exp:"純資産＝資産2,000,000－負債1,200,000＝800,000円。純資産800,000－資本金500,000＝当期純利益300,000円。"},
{id:311,ch:5,themeId:"ch5-4",type:"choice",diff:2,q:"貸借対照表における貸倒引当金の表示として正しいものはどれですか？",opts:["売掛金等から差し引いた金額で表示（間接控除法）","負債の部に表示","費用として別途記載","記載しない"],ans:0,exp:"貸倒引当金は売掛金・受取手形の金額から差し引いて（売掛金×××　貸倒引当金△×××）表示します。これを間接控除法といいます。"},
{id:312,ch:5,themeId:"ch5-4",type:"choice",diff:2,q:"貸借対照表における減価償却累計額の表示として正しいものはどれですか？",opts:["固定資産の金額から差し引いた金額で表示","負債として表示","別途記載","費用として記載"],ans:0,exp:"減価償却累計額は対応する固定資産（建物・備品等）の金額から差し引いて表示します（間接控除法）。"},
{id:313,ch:5,themeId:"ch5-4",type:"calc",diff:2,q:"建物：取得原価2,000,000円、減価償却累計額500,000円。貸借対照表に記載する建物の価額（帳簿価額）はいくらですか？",ans:1500000,unit:"円",exp:"帳簿価額＝取得原価2,000,000－減価償却累計額500,000＝1,500,000円。貸借対照表には帳簿価額（正味価額）で表示します。"},
{id:314,ch:5,themeId:"ch5-4",type:"choice",diff:2,q:"貸借対照表の借方（左側）に記載するものはどれですか？",opts:["資産","負債","純資産","収益"],ans:0,exp:"貸借対照表は左側（借方）に資産、右側（貸方）に負債と純資産を記載します。資産合計＝負債合計＋純資産合計となります。"},
{id:315,ch:5,themeId:"ch5-4",type:"calc",diff:3,q:"B/S：現金200,000、売掛金400,000、備品600,000（累計120,000）、買掛金350,000、借入金400,000、資本金200,000。当期純利益はいくらですか？",ans:130000,unit:"円",exp:"資産合計＝200,000＋400,000＋480,000＝1,080,000。負債合計＝750,000。純資産＝330,000。純利益＝330,000－200,000＝130,000円。"},

// ch5-5 当期純利益の計算
{id:316,ch:5,themeId:"ch5-5",type:"calc",diff:2,q:"収益合計1,500,000円、費用合計1,150,000円。当期純利益はいくらですか？",ans:350000,unit:"円",exp:"当期純利益＝収益合計1,500,000－費用合計1,150,000＝350,000円。"},
{id:317,ch:5,themeId:"ch5-5",type:"calc",diff:3,q:"期首純資産700,000円、期末純資産900,000円、当期引出金50,000円、追加出資100,000円。当期純利益はいくらですか？",ans:150000,unit:"円",exp:"当期純利益＝期末純資産900,000－期首純資産700,000－追加出資100,000＋引出金50,000＝150,000円。"},
{id:318,ch:5,themeId:"ch5-5",type:"choice",diff:2,q:"当期純利益が発生した場合、貸借対照表の純資産にどのような影響がありますか？",opts:["純資産が増加する","純資産が減少する","純資産は変化しない","負債が増加する"],ans:0,exp:"当期純利益は収益から費用を差し引いた利益で、そのまま純資産（繰越利益剰余金など）を増加させます。"},
{id:319,ch:5,themeId:"ch5-5",type:"journal",diff:3,q:"決算において当期純利益200,000円を資本金勘定に振り替えた。（個人企業の場合）",entries:[{dr:"損益",cr:"資本金",amt:200000}],exp:"決算時に損益勘定で計算された純利益200,000円を資本金に振り替えます。損益（借方）、資本金（純資産）増加→貸方。"},
{id:320,ch:5,themeId:"ch5-5",type:"calc",diff:3,q:"損益計算書の当期純利益250,000円。期首純資産600,000円、追加出資80,000円、引出金30,000円。期末純資産はいくらですか？",ans:900000,unit:"円",exp:"期末純資産＝期首600,000＋純利益250,000＋追加出資80,000－引出金30,000＝900,000円。"}
);
